-- packages/web-server/baseline/0001_engine_baseline.sql
--
-- FEAT-ENGINE-BASELINE-2 — clean engine-only baseline.
--
-- Generated by packages/web-server/src/scripts/build-engine-baseline.ts
-- from the engine_schema + engine_system_seed migrations listed in
-- docs/db/engine-baseline-migration-inventory.md. Cartridge-only and
-- repair-only migrations are excluded; mixed migrations have their
-- authored-content lines elided.
--
-- DO NOT edit by hand. Regenerate via:
--   npm --prefix packages/web-server exec -- tsx \\
--     src/scripts/build-engine-baseline.ts
--
-- Application: this file expects a fresh PGlite database with the
-- vector extension already created and the schema_migrations
-- bookkeeping table already present. The bootstrap helper in
-- packages/web-server/src/__tests__/migrations/engineBaseline.test.ts
-- demonstrates the contract; production startup will move to a
-- similar helper in FEAT-ENGINE-BASELINE-3.
--
-- Authored Greenhaven world content (grinhaven-full, Obsidian
-- patches, quickgrin, robot-empty) is NOT installed here. The
-- cartridge install pipeline (FEAT-CART-LIB) owns that.

-- ── 0001_cartridge.sql (engine_schema) ────────────
-- 0001_cartridge.sql — initial cartridge / world schema.
--
-- Design principle: the cartridge IS the world. Entities (people,
-- locations, scenes, items, quests, events) are uniformly modelled in
-- one polymorphic table; everything else hangs off entity ids. This
-- mirrors Grinhaven's existing schema (docs/cli/INTERNALS.md, §2 of
-- prompt-and-patch.md in Grinhaven) so the cartridge port is mostly a
-- data dump, not a redesign.
--
-- The vector extension is required for the npc_memories ANN search.

CREATE EXTENSION IF NOT EXISTS vector;
-- Note: we deliberately do NOT request pg_trgm here. PGlite (the
-- in-process WASM Postgres we use for local dev) doesn't ship trigram
-- support yet. Real Postgres deployments can `CREATE EXTENSION pg_trgm`
-- in a follow-up migration if/when full-text-on-name search becomes a
-- bottleneck.

-- ── Entities ───────────────────────────────────────────────────────────
-- Polymorphic. `kind` = 'person' | 'location' | 'scene' | 'item' |
-- 'quest' | 'event' | 'district' | 'service' | 'thread'. The free-form
-- `profile` JSONB carries kind-specific metadata (species, narrator
-- briefs, archetype, …). `tags` is a fast-search side-channel.

CREATE TABLE IF NOT EXISTS entities (
    id            BIGSERIAL PRIMARY KEY,
    kind          TEXT NOT NULL,
    display_name  TEXT NOT NULL,
    summary       TEXT,
    profile       JSONB NOT NULL DEFAULT '{}'::jsonb,
    tags          TEXT[] NOT NULL DEFAULT '{}',
    created_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at    TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_entities_kind ON entities(kind);
CREATE INDEX IF NOT EXISTS idx_entities_tags ON entities USING gin(tags);
CREATE INDEX IF NOT EXISTS idx_entities_profile ON entities USING gin(profile jsonb_path_ops);
-- (idx_entities_name_trgm dropped — needs pg_trgm; see note at top.)

-- ── Runtime field declarations ─────────────────────────────────────────
-- Schema for the live state-machine. Each row says "this entity has a
-- field of this name + type, default value, scope". Values live in
-- runtime_values below.

CREATE TABLE IF NOT EXISTS runtime_fields (
    id              BIGSERIAL PRIMARY KEY,
    owner_entity_id BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
    field_key       TEXT   NOT NULL,
    -- Mirrors Grinhaven's value_type taxonomy.
    value_type      TEXT   NOT NULL CHECK (value_type IN
                       ('int','float','bool','string','enum',
                        'entity_ref','json','dice')),
    default_value   JSONB,
    allowed_values  JSONB,
    scope           TEXT   NOT NULL DEFAULT 'session' CHECK (scope IN
                       ('turn','scene','session','journey','permanent')),
    description     TEXT,
    UNIQUE (owner_entity_id, field_key)
);

CREATE INDEX IF NOT EXISTS idx_runtime_fields_owner ON runtime_fields(owner_entity_id);

-- ── Runtime values ─────────────────────────────────────────────────────
-- Current value for each field. One row per declared field; INSERT on
-- first-use, UPDATE thereafter.

CREATE TABLE IF NOT EXISTS runtime_values (
    field_id    BIGINT PRIMARY KEY REFERENCES runtime_fields(id) ON DELETE CASCADE,
    value       JSONB  NOT NULL,
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT now(),
    -- Source of the last write — useful for telemetry. 'cartridge_seed',
    -- 'transition', 'tool_apply', 'manual', etc.
    source      TEXT
);

-- ── Inventory ──────────────────────────────────────────────────────────
-- Who carries what. Counts >= 0 enforced; negatives are caught at
-- write-time so the world never has -3 gold pieces.

CREATE TABLE IF NOT EXISTS inventory_entries (
    holder_entity_id  BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
    item_entity_id    BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
    count             INTEGER NOT NULL CHECK (count >= 0),
    metadata          JSONB DEFAULT '{}'::jsonb,
    PRIMARY KEY (holder_entity_id, item_entity_id)
);

-- ── Transitions ────────────────────────────────────────────────────────
-- Forward-chaining rules. Re-evaluated to fixpoint after each model
-- patch. `when_json` is a list of predicates over runtime fields,
-- `set_json` is the patch to apply when ALL predicates match.

CREATE TABLE IF NOT EXISTS transitions (
    id               BIGSERIAL PRIMARY KEY,
    owner_entity_id  BIGINT REFERENCES entities(id) ON DELETE CASCADE,
    description      TEXT,
    when_json        JSONB NOT NULL,
    set_json         JSONB NOT NULL,
    goto_entity_id   BIGINT REFERENCES entities(id),
    priority         INTEGER NOT NULL DEFAULT 0,
    consume_flags    TEXT[] DEFAULT '{}'
);

CREATE INDEX IF NOT EXISTS idx_transitions_owner ON transitions(owner_entity_id);

-- ── Entity instructions ────────────────────────────────────────────────
-- Cartridge-side hints surfaced into the prompt. Two flavours:
--   - `instruction_json.text`   → narrative rule shown to the model.
--   - `instruction_json.action` → quick-action button shown to the player.
-- `applies_when` is a list of predicates evaluated each turn — a row
-- only enters the prompt when its conditions match.

CREATE TABLE IF NOT EXISTS entity_instructions (
    id                BIGSERIAL PRIMARY KEY,
    owner_entity_id   BIGINT REFERENCES entities(id) ON DELETE CASCADE,
    priority          INTEGER NOT NULL DEFAULT 0,
    applies_when      JSONB DEFAULT '[]'::jsonb,
    instruction_json  JSONB NOT NULL
);

CREATE INDEX IF NOT EXISTS idx_entity_instructions_owner ON entity_instructions(owner_entity_id);

-- ── Sessions / chat history ────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS sessions (
    id          TEXT PRIMARY KEY,                -- the UUID we generate
    started_at  TIMESTAMPTZ NOT NULL DEFAULT now(),
    last_seen   TIMESTAMPTZ NOT NULL DEFAULT now(),
    metadata    JSONB DEFAULT '{}'::jsonb        -- model, auth, …
);

CREATE TABLE IF NOT EXISTS chat_messages (
    id                BIGSERIAL PRIMARY KEY,
    session_id        TEXT NOT NULL REFERENCES sessions(id) ON DELETE CASCADE,
    author_entity_id  BIGINT REFERENCES entities(id) ON DELETE SET NULL,
    -- 'player' | 'npc' | 'system' | 'narrator'
    tone              TEXT NOT NULL,
    text              TEXT NOT NULL,
    turn_index        INTEGER NOT NULL,
    payload           JSONB DEFAULT '{}'::jsonb,  -- patch report, dice, …
    created_at        TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_chat_messages_session_turn
    ON chat_messages(session_id, turn_index);
CREATE INDEX IF NOT EXISTS idx_chat_messages_author
    ON chat_messages(author_entity_id);

-- ── NPC memory bank ────────────────────────────────────────────────────
-- Long-term memories owned by NPCs (or any entity). About is optional —
-- a memory may be ambient ("the lamp went out at midnight") with no
-- subject. Embedding is optional too: writes happen first, embedding
-- runs async via a worker that backfills the vector.
--
-- Embedding dimension: 768 matches text-embedding-004 (Google) and
-- text-embedding-3-small (OpenAI). If we move to a model with a
-- different dim later we'd need a migration.

CREATE TABLE IF NOT EXISTS npc_memories (
    id                BIGSERIAL PRIMARY KEY,
    owner_entity_id   BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
    about_entity_id   BIGINT REFERENCES entities(id) ON DELETE SET NULL,
    text              TEXT NOT NULL,
    importance        REAL NOT NULL DEFAULT 0.5
                          CHECK (importance >= 0 AND importance <= 1),
    tags              TEXT[] NOT NULL DEFAULT '{}',
    embedding         vector(768),
    embedded_at       TIMESTAMPTZ,
    sensitive         BOOLEAN NOT NULL DEFAULT false,
    metadata          JSONB DEFAULT '{}'::jsonb,
    created_at        TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_npc_memories_owner       ON npc_memories(owner_entity_id);
CREATE INDEX IF NOT EXISTS idx_npc_memories_about       ON npc_memories(about_entity_id);
CREATE INDEX IF NOT EXISTS idx_npc_memories_tags        ON npc_memories USING gin(tags);
CREATE INDEX IF NOT EXISTS idx_npc_memories_importance  ON npc_memories(importance DESC);
-- ANN index. Created with conservative HNSW params; tune `ef_search`
-- per query if recall lags.
CREATE INDEX IF NOT EXISTS idx_npc_memories_embedding
    ON npc_memories USING hnsw (embedding vector_cosine_ops)
    WITH (m = 16, ef_construction = 64);

-- ── Migrations table ───────────────────────────────────────────────────
-- Bookkeeping for the in-process migration runner. The runner consults
-- this table on startup; only files whose name isn't recorded run.

CREATE TABLE IF NOT EXISTS schema_migrations (
    name        TEXT PRIMARY KEY,
    applied_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- ── 0002_litrpg.sql (engine_schema) ────────────
-- 0002_litrpg.sql — LitRPG world model.
--
-- Adds:
--   - Player progression (XP, level, stats, skills, equipment, reputation).
--   - Per-player overlays on shared NPC state (Mikka treats each player
--     individually even though her global mood is shared).
--   - Tool-invocation audit log (every AI mutation traceable).
--   - Content tables (classes, skills, factions) the cartridge seed fills.
--
-- "One shared world" model: entities (NPCs, locations, items) are global.
-- Player progression and per-player NPC interactions live in dedicated
-- tables keyed by player_id.

-- ── Per-player runtime overlay ─────────────────────────────────────────
-- For fields that must differ between players (e.g. "did THIS player
-- pay Mikka?"), the value lives here instead of runtime_values.
-- runtime_fields.scope_per_player decides which table the writer hits;
-- readers union the two with overlay winning.

ALTER TABLE runtime_fields
    ADD COLUMN IF NOT EXISTS scope_per_player BOOLEAN NOT NULL DEFAULT false;

CREATE TABLE IF NOT EXISTS runtime_player_overlay (
    field_id    BIGINT NOT NULL REFERENCES runtime_fields(id) ON DELETE CASCADE,
    player_id   BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
    value       JSONB  NOT NULL,
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT now(),
    source      TEXT,
    PRIMARY KEY (field_id, player_id)
);

CREATE INDEX IF NOT EXISTS idx_runtime_player_overlay_player
    ON runtime_player_overlay(player_id);

-- ── Players ────────────────────────────────────────────────────────────
-- A player is an entity (kind='player') with a row here. Splitting from
-- entities lets us index/normalise progression columns; the entity row
-- still carries display_name, profile, tags so generic entity tools work.

CREATE TABLE IF NOT EXISTS players (
    entity_id              BIGINT PRIMARY KEY REFERENCES entities(id) ON DELETE CASCADE,
    -- Stable identity. UUID is what the client persists in localStorage.
    -- Recovery code is shown ONCE at signup; hashed here so a leak of
    -- this table doesn't hand out logins. Verification is bcrypt-style
    -- compare in app code.
    public_id              UUID NOT NULL UNIQUE,
    recovery_code_hash     TEXT,
    -- Class assigned at start; can change via class-change tools later.
    class_id               BIGINT REFERENCES entities(id),  -- entity[kind='class']
    current_xp             BIGINT NOT NULL DEFAULT 0 CHECK (current_xp >= 0),
    current_level          INTEGER NOT NULL DEFAULT 1 CHECK (current_level >= 1),
    current_hp             INTEGER NOT NULL DEFAULT 10 CHECK (current_hp >= 0),
    max_hp                 INTEGER NOT NULL DEFAULT 10 CHECK (max_hp > 0),
    current_location_id    BIGINT REFERENCES entities(id),  -- entity[kind='location']
    current_scene_id       BIGINT REFERENCES entities(id),  -- entity[kind='scene']
    metadata               JSONB DEFAULT '{}'::jsonb,
    created_at             TIMESTAMPTZ NOT NULL DEFAULT now(),
    last_seen              TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_players_class       ON players(class_id);
CREATE INDEX IF NOT EXISTS idx_players_location    ON players(current_location_id);

-- ── Stats ──────────────────────────────────────────────────────────────
-- Six classic LitRPG stats — STR/DEX/CON/INT/WIS/CHA. Stored open-form
-- via stat_key so a cartridge can introduce custom stats without a
-- migration. base = innate, current = base + temp modifiers.

CREATE TABLE IF NOT EXISTS player_stats (
    player_id   BIGINT NOT NULL REFERENCES players(entity_id) ON DELETE CASCADE,
    stat_key    TEXT NOT NULL,
    base        INTEGER NOT NULL DEFAULT 10,
    current     INTEGER NOT NULL DEFAULT 10,
    PRIMARY KEY (player_id, stat_key)
);

-- ── Skills ─────────────────────────────────────────────────────────────
-- skill_entity_id points at entities[kind='skill']. Each player has 0..N
-- ranks per skill. rank=0 means known but unleveled.

CREATE TABLE IF NOT EXISTS player_skills (
    player_id          BIGINT NOT NULL REFERENCES players(entity_id) ON DELETE CASCADE,
    skill_entity_id    BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
    rank               INTEGER NOT NULL DEFAULT 0 CHECK (rank >= 0),
    unlocked_at        TIMESTAMPTZ NOT NULL DEFAULT now(),
    metadata           JSONB DEFAULT '{}'::jsonb,
    PRIMARY KEY (player_id, skill_entity_id)
);

-- ── Equipment ──────────────────────────────────────────────────────────
-- One row per occupied slot. Items live in entities[kind='item'] with
-- their stat modifiers/rarity in profile JSONB.

CREATE TABLE IF NOT EXISTS player_equipment (
    player_id          BIGINT NOT NULL REFERENCES players(entity_id) ON DELETE CASCADE,
    slot               TEXT NOT NULL,
    item_entity_id     BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
    equipped_at        TIMESTAMPTZ NOT NULL DEFAULT now(),
    PRIMARY KEY (player_id, slot)
);

-- ── XP audit log ───────────────────────────────────────────────────────
-- Every XP grant recorded with reason + the tool that issued it. Lets
-- us trace "where did this 350 XP come from?" and detect AI-loop
-- exploits where the model awards XP for trivial actions.

CREATE TABLE IF NOT EXISTS player_xp_log (
    id                 BIGSERIAL PRIMARY KEY,
    player_id          BIGINT NOT NULL REFERENCES players(entity_id) ON DELETE CASCADE,
    amount             INTEGER NOT NULL,
    reason             TEXT NOT NULL,
    awarded_by_tool    TEXT,
    awarded_at         TIMESTAMPTZ NOT NULL DEFAULT now(),
    metadata           JSONB DEFAULT '{}'::jsonb
);

CREATE INDEX IF NOT EXISTS idx_player_xp_log_player ON player_xp_log(player_id, awarded_at DESC);

-- ── Faction reputation ─────────────────────────────────────────────────
-- Linear value, semantics decided per-game. Caps & decay live in tools.

CREATE TABLE IF NOT EXISTS faction_reputation (
    player_id          BIGINT NOT NULL REFERENCES players(entity_id) ON DELETE CASCADE,
    faction_entity_id  BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
    value              INTEGER NOT NULL DEFAULT 0,
    updated_at         TIMESTAMPTZ NOT NULL DEFAULT now(),
    PRIMARY KEY (player_id, faction_entity_id)
);

-- ── Quests (per-player progress) ───────────────────────────────────────
-- The quest definition lives in entities[kind='quest']. A player's
-- progress in that quest is here. status: 'unseen' | 'offered' |
-- 'active' | 'completed' | 'failed'.

CREATE TABLE IF NOT EXISTS player_quests (
    player_id          BIGINT NOT NULL REFERENCES players(entity_id) ON DELETE CASCADE,
    quest_entity_id    BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
    status             TEXT NOT NULL DEFAULT 'offered'
                          CHECK (status IN ('unseen','offered','active','completed','failed')),
    current_phase      INTEGER NOT NULL DEFAULT 0,
    started_at         TIMESTAMPTZ,
    completed_at       TIMESTAMPTZ,
    metadata           JSONB DEFAULT '{}'::jsonb,
    PRIMARY KEY (player_id, quest_entity_id)
);

CREATE INDEX IF NOT EXISTS idx_player_quests_status
    ON player_quests(player_id, status);

-- ── Tool invocation audit ──────────────────────────────────────────────
-- Every AI tool call lands here. Lets us replay a turn, debug "why did
-- the world end up like this", and detect runaway loops where the
-- model called award_xp twenty times in a row.

CREATE TABLE IF NOT EXISTS tool_invocations (
    id              BIGSERIAL PRIMARY KEY,
    session_id      TEXT REFERENCES sessions(id) ON DELETE SET NULL,
    player_id       BIGINT REFERENCES entities(id) ON DELETE SET NULL,
    turn_id         TEXT,
    tool_name       TEXT NOT NULL,
    args            JSONB NOT NULL,
    result          JSONB,
    error           TEXT,
    duration_ms     INTEGER,
    invoked_at      TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_tool_invocations_session
    ON tool_invocations(session_id, invoked_at);
CREATE INDEX IF NOT EXISTS idx_tool_invocations_player
    ON tool_invocations(player_id, invoked_at DESC);

-- ── Players need session linkage ───────────────────────────────────────
-- Each session belongs to a player (foreign key, nullable for boot
-- compat — old sessions remain valid). Newly created sessions get
-- assigned in code.

ALTER TABLE sessions
    ADD COLUMN IF NOT EXISTS player_id BIGINT REFERENCES entities(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS idx_sessions_player ON sessions(player_id);

-- ── Helper: XP curve ───────────────────────────────────────────────────
-- Quadratic curve — xp_required_for_level(L) = 100 * L^2. Gives:
--   1 → 2: 100 XP
--   5 → 6: 2500 XP
--   10 → 11: 10000 XP
--   20 → 21: 40000 XP
-- Steep enough to feel grindy at high levels without making early game
-- a slog. SQL function so all callers (tools + reports) agree.

CREATE OR REPLACE FUNCTION xp_required_for_level(level INTEGER)
RETURNS BIGINT
LANGUAGE SQL
IMMUTABLE
AS $$
    SELECT (100 * level * level)::BIGINT
$$;

CREATE OR REPLACE FUNCTION level_for_xp(xp BIGINT)
RETURNS INTEGER
LANGUAGE SQL
IMMUTABLE
AS $$
    -- Solve 100 * L^2 <= xp → L = floor(sqrt(xp / 100)). Min level 1.
    SELECT GREATEST(1, FLOOR(SQRT(xp::DOUBLE PRECISION / 100.0))::INTEGER)
$$;

-- ── 0004_sequence_fix.sql (engine_schema) ────────────
-- 0004_sequence_fix.sql — push the entities BIGSERIAL counter past the
-- seeded cartridge block so future inserts don't collide with fixed
-- ids reserved in 0003 (locations 100-199, NPCs 200-299, items 300-399,
-- scenes 400-499, quests 500-599, classes 600-699, skills 700-799,
-- factions 800-899). 1000 is the floor for everything BIGSERIAL hands
-- out from now on (players, AI-spawned NPCs, dynamic loot).

SELECT setval('entities_id_seq', 1000, false);

-- Same for runtime_fields: cartridge reserves 2000-2999 for scene
-- fields, 2100-2199 for NPC fields. Future field declarations issued
-- by tools should sit in 3000+.
SELECT setval('runtime_fields_id_seq', 3000, false);

-- And transitions / entity_instructions, both seeded with explicit
-- ids in the 1-999 range. Push their sequences past 1000 too so
-- subsequent dynamic inserts don't fight cartridge ones.
SELECT setval('transitions_id_seq', 1000, false);
SELECT setval('entity_instructions_id_seq', 1000, false);

-- ── 0007_dialogue_mode.sql (engine_schema) ────────────
-- 0007_dialogue_mode.sql — dialogue-vs-ambient model.
--
-- Locations are broadcast channels; NPCs are focus modes.
--
--   * When a player is NOT in dialogue, their input goes to the
--     location's ambient narrator. Their narrate writes land with
--     npc_entity_id = NULL — visible to anyone reading the location
--     feed.
--
--   * When a player ENTERS a dialogue with an NPC, narrate writes
--     get tagged with npc_entity_id = X. Their dialogue thread is
--     `(player_id, npc_entity_id)`-scoped: each player has their own
--     ongoing chat with the NPC, even when several players are
--     talking to the same NPC at once. Other players in the same
--     location see these dialogue lines too (read-only, as activity)
--     — they're not silently private.
--
--   * Location ambient is muted FOR THE FOCUSED PLAYER while they're
--     in dialogue (their model context filters it out). It still
--     happens for everyone else.
--
-- Index strategy: location feed reads are
-- `(location_entity_id, npc_entity_id IS NULL, turn_index DESC)`;
-- per-player dialogue reads are
-- `(player_author / npc_entity_id, turn_index DESC)`. Two partial
-- indexes cover both.

ALTER TABLE chat_messages
    ADD COLUMN IF NOT EXISTS location_entity_id BIGINT
        REFERENCES entities(id) ON DELETE SET NULL,
    ADD COLUMN IF NOT EXISTS npc_entity_id BIGINT
        REFERENCES entities(id) ON DELETE SET NULL,
    ADD COLUMN IF NOT EXISTS player_id BIGINT
        REFERENCES entities(id) ON DELETE SET NULL;

-- Backfill: best-effort tag of pre-existing rows. We don't have the
-- original location/npc/player linkage, but we DO have author_entity_id
-- and session_id. For the demo data, every player is in Quickgrin Lane
-- and the only NPC who's spoken is Mikka, so we tag heuristically:
--   * if author is Mikka (200) → npc_entity_id = 200, location = 100
--   * if author is a location (100/101) → location_entity_id = author
--   * else (player or null) → leave nulls; not enough info
UPDATE chat_messages
   SET npc_entity_id      = CASE WHEN author_entity_id = 200 THEN 200 ELSE NULL END,
       location_entity_id = CASE
                              WHEN author_entity_id = 200 THEN 100
                              WHEN author_entity_id IN (100, 101) THEN author_entity_id
                              ELSE NULL
                            END
 WHERE npc_entity_id IS NULL AND location_entity_id IS NULL;

CREATE INDEX IF NOT EXISTS idx_chat_messages_location_ambient
    ON chat_messages(location_entity_id, turn_index DESC)
    WHERE npc_entity_id IS NULL;

CREATE INDEX IF NOT EXISTS idx_chat_messages_dialogue
    ON chat_messages(player_id, npc_entity_id, turn_index DESC)
    WHERE npc_entity_id IS NOT NULL;

-- Player's current focus. NULL = listening to the location ambient.
-- Non-null = in dialogue with this NPC; their turns route through
-- that thread until they end the dialogue.
ALTER TABLE players
    ADD COLUMN IF NOT EXISTS dialogue_partner_id BIGINT
        REFERENCES entities(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS idx_players_dialogue_partner
    ON players(dialogue_partner_id)
    WHERE dialogue_partner_id IS NOT NULL;

-- ── 0008_entity_aliases.sql (engine_schema) ────────────
-- 0008_entity_aliases.sql — store alternate names for cartridge
-- entities so the model can call them in the player's language and
-- still hit a buttonable @-mention.
--
-- Schema convention: `entities.profile.aliases` is a flat string[] of
-- alternative names the substring-scan in narrate.ts / synthesiseNarrate
-- accepts in addition to display_name. Keep them in the language(s)
-- you expect players to play in. Add more later as the cartridge
-- grows multilingual.
--
-- The scan in narrate.ts treats every alias the same as display_name:
-- if the narrate text contains `@<alias>` exactly (substring match,
-- no normalisation), the entity is resolved by id and the matched
-- string becomes the @-button label in the UI.

UPDATE entities
   SET profile = profile || jsonb_build_object('aliases', jsonb_build_array(
     'Микка Хитрогрин', 'Микка'
   ))
 WHERE id = 200;  -- Mikka Quickgrin

UPDATE entities
   SET profile = profile || jsonb_build_object('aliases', jsonb_build_array(
     'Переулок Хитрогрин', 'Куикгрин Лейн'
   ))
 WHERE id = 100;  -- Quickgrin Lane

UPDATE entities
   SET profile = profile || jsonb_build_object('aliases', jsonb_build_array(
     'Бархатные Кабинки'
   ))
 WHERE id = 101;  -- Velvet Booths

UPDATE entities
   SET profile = profile || jsonb_build_object('aliases', jsonb_build_array(
     'Золотая Монета', 'Монета'
   ))
 WHERE id = 300;  -- Gold Coin

UPDATE entities
   SET profile = profile || jsonb_build_object('aliases', jsonb_build_array(
     'Потухший Фонарь', 'Тёмный Фонарь'
   ))
 WHERE id = 301;  -- Extinguished Lamp

UPDATE entities
   SET profile = profile || jsonb_build_object('aliases', jsonb_build_array(
     E'Личная цена Микки', E'Цена Микки'
   ))
 WHERE id = 500;  -- Mikka's Private Price (quest)

UPDATE entities
   SET profile = profile || jsonb_build_object('aliases', jsonb_build_array(
     E'Частные переговоры с Миккой'
   ))
 WHERE id = 400;  -- Mikka's Private Negotiation (scene)

-- ── 0010_npc_stats.sql (engine_schema) ────────────
-- 0010_npc_stats.sql — D&D-style ability scores for NPCs.
--
-- Mirror of `player_stats` (six classic abilities: STR / DEX / CON /
-- INT / WIS / CHA), keyed by entity id. Mod is computed
-- on-the-fly: floor((current - 10) / 2). The combat tools don't read
-- this table directly — the model does, via the turnContext preamble
-- (PEOPLE HERE prints "STR 8 (-1), DEX 14 (+2), …") and uses the
-- modifier as the second argument to `dice_check`.
--
-- AC is a separate runtime_field per actor so it can shift with
-- armour, buffs, debuffs. Default is a static integer; tools that
-- equip / debuff later can write through `apply_runtime_field_patch`.

CREATE TABLE IF NOT EXISTS npc_stats (
    npc_entity_id BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
    stat_key      TEXT   NOT NULL,
    base          INT    NOT NULL,
    current       INT    NOT NULL,
    PRIMARY KEY (npc_entity_id, stat_key)
);

CREATE INDEX IF NOT EXISTS idx_npc_stats_owner ON npc_stats(npc_entity_id);

-- [engine-baseline] elided: cartridge content removed for clean baseline.

-- ── 0012_dice_cooldowns.sql (engine_schema) ────────────
-- 0012_dice_cooldowns.sql — 24h cooldown on non-combat ability checks.
--
-- Pattern: a player tries to seduce / persuade / shove / pick-lock
-- a specific target. Failed (or succeeded) — they wait a day before
-- they can attempt the SAME check on the SAME target again. Combat
-- rolls (attack, damage, save) are exempt: hits land instantly and
-- you can keep swinging.
--
-- The dice_check tool checks this table BEFORE rolling when args
-- include `target_id` and `category='check'`. If a row exists with
-- last_rolled_at within the cooldown window, the call returns early
-- with `cooldown=true` + `next_attempt_allowed_at`.

CREATE TABLE IF NOT EXISTS dice_check_cooldowns (
    player_id        BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
    target_entity_id BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
    /**
     * Free-form key the model passes — typically the social action
     * name ('seduce', 'persuade', 'intimidate') or the item check
     * ability+verb ('STR_shove', 'DEX_pick'). Lowercased + trimmed at
     * write/read time so capitalisation drift doesn't matter.
     */
    check_kind       TEXT   NOT NULL,
    last_rolled_at   TIMESTAMPTZ NOT NULL DEFAULT now(),
    last_outcome     TEXT,
    PRIMARY KEY (player_id, target_entity_id, check_kind)
);

CREATE INDEX IF NOT EXISTS idx_dice_cooldowns_player_target
    ON dice_check_cooldowns(player_id, target_entity_id);

-- ── 0014_player_status.sql (engine_schema) ────────────
-- 0014_player_status.sql — combat status flags on the player.
--
-- Mirrors the NPC convention from 0013 (stunned runtime field) but
-- on a column on `players` for tighter typing. Future status effects
-- (prone, poisoned, frightened) can land as additional columns OR
-- migrate to a single JSONB `status_effects` blob — keep it as a
-- bool column for now since `stunned` is the only one combat reads.
--
-- Combat resolution checks this BEFORE Phase 1 (player swing).
-- Stunned → player skips their action, the flag auto-clears at the
-- end of the round so it lasts exactly one round.

ALTER TABLE players
    ADD COLUMN IF NOT EXISTS is_stunned BOOLEAN NOT NULL DEFAULT false;

-- ── 0015_turn_telemetry.sql (engine_schema) ────────────
-- 0015_turn_telemetry.sql — per-turn cost + latency tracking.
--
-- One row per (turn, role) — broker and narrator are separate rows so
-- we can isolate which stage dominates cost. Scripted-only turns have
-- only a narrator row.
--
-- cost_usd is computed at insert-time from token counts × the role's
-- model rate. Pricing constants live in src/ai/pricing.ts.

CREATE TABLE IF NOT EXISTS turn_telemetry (
    id BIGSERIAL PRIMARY KEY,
    session_id UUID NOT NULL,
    turn_id TEXT NOT NULL,
    role TEXT NOT NULL,                -- 'broker' | 'narrator' | 'narrator-scripted'
    model_id TEXT NOT NULL,
    thinking BOOLEAN NOT NULL DEFAULT false,
    input_tokens INTEGER NOT NULL,
    output_tokens INTEGER NOT NULL,
    cache_hit_tokens INTEGER NOT NULL DEFAULT 0,
    cache_miss_tokens INTEGER NOT NULL DEFAULT 0,
    duration_ms INTEGER NOT NULL,
    cost_usd NUMERIC(12, 8) NOT NULL,
    tier TEXT,                          -- T0..T4 from cost-optimization tiers, NULL until classifier lands
    recorded_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_turn_telemetry_session_turn
  ON turn_telemetry(session_id, turn_id);
CREATE INDEX IF NOT EXISTS idx_turn_telemetry_recorded_at
  ON turn_telemetry(recorded_at DESC);

-- ── 0016_telemetry_player.sql (engine_schema) ────────────
-- 0016_telemetry_player.sql — attribute telemetry to players for usage admin.
--
-- Spec 05 introduced `turn_telemetry` without a player_id column.
-- Spec 13's per-player usage endpoint needs that attribution. Existing
-- rows stay NULL; new rows from turnRunnerV2 record the player.

ALTER TABLE turn_telemetry ADD COLUMN IF NOT EXISTS player_id INTEGER;
CREATE INDEX IF NOT EXISTS idx_turn_telemetry_player_recorded
  ON turn_telemetry(player_id, recorded_at DESC);

-- ── 0017_i18n.sql (engine_schema) ────────────
-- 0017_i18n.sql — multilingual cartridge text fields.
--
-- The cartridge stores entity / instruction text in a single canonical
-- string (display_name, summary, profile.*, instruction_json.text). To
-- serve players in any language without forking the cartridge per
-- locale, we add a sparse JSONB column on each row:
--
--   entities.i18n              :: { <fieldName>: { <lang>: <value> } }
--   entity_instructions.i18n   :: same shape
--
-- Convention: `fieldName` is the canonical name of the localized field
-- — 'display_name', 'summary', or a profile key like 'narrator_brief'
-- / 'speech_style'. Empty object means "no translations exist; fall
-- back to the base column".
--
-- Engine resolves via src/i18n.ts: locale → 'en' → base column. Cartridge
-- authors fill `i18n` as they translate; nothing breaks for entries
-- that stay monolingual.
--
-- players.preferred_language stores the player's chosen locale (ISO 639
-- short code: 'en', 'ru', 'ja', 'zh', …). Per-turn `language` param in
-- POST /turn overrides; this column is the persistent fallback.

ALTER TABLE entities
    ADD COLUMN IF NOT EXISTS i18n JSONB NOT NULL DEFAULT '{}'::jsonb;

ALTER TABLE entity_instructions
    ADD COLUMN IF NOT EXISTS i18n JSONB NOT NULL DEFAULT '{}'::jsonb;

ALTER TABLE players
    ADD COLUMN IF NOT EXISTS preferred_language TEXT;

-- ── 0018_cartridge_meta.sql (engine_schema) ────────────
-- 0018_cartridge_meta.sql — engine ↔ cartridge decoupling.
--
-- The engine should not hardcode "starting location is 100", "currency
-- is item 300", "Mikka's mood lives at field 2101". Those are cartridge
-- decisions. This table lets the engine read them at runtime so any
-- cartridge can ship its own values without touching engine source.
--
-- Convention: keys are stable identifiers; values are JSONB. Schema
-- versions live in cartridge_id / cartridge_version so the engine can
-- gate features by cartridge generation if needed later.
--
-- Below we seed the values that match Quickgrin Lane today (the
-- numbers previously hardcoded in playerService.ts and index.ts).
-- A second cartridge would ship its own seed migration overwriting
-- these rows, or the loader would re-INSERT on cartridge import.

CREATE TABLE IF NOT EXISTS cartridge_meta (
    key         TEXT PRIMARY KEY,
    value       JSONB NOT NULL,
    description TEXT,
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- [engine-baseline] elided: cartridge content removed for clean baseline.

-- ── 0026_conditions_field.sql (engine_schema) ────────────
-- Spec 17 — Combat Conditions & Tags layer.
--
-- Adds a 'conditions' JSONB array runtime_field to every kind='person'
-- entity. Schema:
--   [
--     { "tag": "bleeding", "applied_turn": N, "expires_turn": N+3,
--       "severity": 1..3, "source": "player:<entity_id>" },
--     ...
--   ]
-- Empty array = no conditions. transitionEngine.ts decrements on each
-- turn boundary; entries whose expires_turn <= currentTurn are dropped.
--
-- Field ID claim: 8000 + entity.id (per cross-cutting-concerns.md
-- registry — 8000+ block reserved for spec 17 conditions).

INSERT INTO runtime_fields
  (id, owner_entity_id, field_key, value_type, default_value, allowed_values, scope, scope_per_player, description)
SELECT
  8000 + e.id,
  e.id,
  'conditions',
  'json',
  '[]'::jsonb,
  NULL,
  'session',
  false,
  'Active combat conditions: bleeding, stunned, off-balance, disarmed, prone. Decremented per turn.'
FROM entities e
WHERE e.kind = 'person'
  AND NOT EXISTS (
    SELECT 1 FROM runtime_fields rf
    WHERE rf.owner_entity_id = e.id AND rf.field_key = 'conditions'
  );

-- ── 0027_strings_field.sql (engine_schema) ────────────
-- Spec 18 — Strings (emotional leverage between player and NPC).
--
-- Adds 'strings' JSONB to every kind='person' entity. Schema:
--   { "<player_entity_id>": <int>, ... }
-- The OWNER of the runtime_field is one side of the bond; the KEYS are
-- the other side's player_id. v1 is symmetric: a single per-NPC map
-- carries player→NPC strings.
--
-- Field ID claim: 9000 + entity.id (per cross-cutting-concerns.md
-- registry — 9000+ block reserved for spec 18 strings).

INSERT INTO runtime_fields
  (id, owner_entity_id, field_key, value_type, default_value, allowed_values, scope, scope_per_player, description)
SELECT
  9000 + e.id,
  e.id,
  'strings',
  'json',
  '{}'::jsonb,
  NULL,
  'permanent',
  false,
  'Emotional leverage strings keyed by counterparty player_id. Earned in intimate / dramatic beats, spent for +1d on social rolls.'
FROM entities e
WHERE e.kind = 'person'
  AND NOT EXISTS (
    SELECT 1 FROM runtime_fields rf
    WHERE rf.owner_entity_id = e.id AND rf.field_key = 'strings'
  );

