-- ── 0031_player_profile_schema.sql (engine_schema) ────────────
-- Spec 26 — player profile schema. Lives in entities.profile (where
-- kind='player'). New endpoints in src/routes/profile.ts read/patch
-- this; the wizard fills it; turnContext surfaces every field in the
-- PLAYER preamble.
--
-- Backfill any existing player entities with an empty profile shell
-- so new endpoints don't crash on null reads.

UPDATE entities
   SET profile = COALESCE(profile, '{}'::jsonb) || jsonb_build_object(
         'identity', '{}'::jsonb,
         'physical', '{}'::jsonb,
         'background', '{}'::jsonb,
         'created', false
       )
 WHERE kind = 'player'
   AND (profile IS NULL OR NOT (profile ? 'created'));

-- ── 0032_class_profile_and_stats.sql (engine_schema) ────────────
-- Spec 27 — Class profile schema + skill-name-keyed proficiency.
--
-- Existing player_stats (0002_litrpg.sql) is long-format
-- (player_id, stat_key, base, current). We don't reshape it; the new
-- character/:id/stats endpoint writes 6 rows in one round-trip.
-- The 5e proficiency bonus is hard-coded to 2 at level 1; spec 36
-- replaces with the xp_thresholds lookup (deferred, per cross-cutting
-- registry).
--
-- NEW table: player_proficient_skills, keyed by skill_name (D&D 5e
-- canonical 18 skills). Avoids the existing player_skills' dependence
-- on cartridge skill_entity_ids that we don't author here.

-- [engine-baseline] elided: cartridge content removed for clean baseline.


-- [engine-baseline] elided: cartridge content removed for clean baseline.


CREATE TABLE IF NOT EXISTS player_proficient_skills (
  player_id BIGINT NOT NULL REFERENCES players(entity_id) ON DELETE CASCADE,
  skill_name TEXT NOT NULL,
  proficiency_level INTEGER NOT NULL DEFAULT 1, -- 1=proficient, 2=expertise
  PRIMARY KEY (player_id, skill_name)
);

-- ── 0033_npc_portraits_and_world_atmosphere.sql (engine_schema) ────────────
-- Spec 32 — atmospheric runtime fields + per-NPC portrait scaffold.
--
-- Adds time_of_day / weather / world_time_minutes runtime fields on
-- the world entity (id=10, seeded by 0021_world_entity.sql). The
-- transition engine ticks world_time_minutes by ~10 per turn and
-- recomputes time_of_day. Each runtime mutation emits SSE so the UI
-- atmosphere overlay smooth-transitions.
--
-- Each kind='person' entity gets a `profile.portrait_set` with a single
-- 'default' slot pre-populated null. Cartridge author overrides per-
-- emotion URLs.

UPDATE entities
   SET profile = COALESCE(profile, '{}'::jsonb) ||
                 jsonb_build_object('portrait_set', jsonb_build_object('default', null))
 WHERE kind = 'person'
   AND NOT (profile ? 'portrait_set');

