-- ── 0041_xp_levels.sql (engine_schema) ────────────
-- Spec 36 §2 — XP / level scaling. The hard-coded
-- proficiency_bonus = 2 in spec 27 collapses D&D 5e's level curve
-- (lvl 1-4=+2, 5-8=+3, 9-12=+4, 13-16=+5, 17-20=+6). We expose the
-- canonical SRD table so turnContext computes prof_bonus from the
-- player's current level.
--
-- Field-id ABI: spec 35 already used 12100+entity / 12200+entity for
-- death-save counters. We allocate the 13xxx block here:
--   13100 + entity_id  →  xp
--   13200 + entity_id  →  level
-- (Spec 36's literal IDs 12100/12101 collide with spec 35; deviation
-- documented in EXECUTION_LOG.)

CREATE TABLE IF NOT EXISTS xp_thresholds (
  level             INT PRIMARY KEY,
  xp_required       INT NOT NULL,
  proficiency_bonus INT NOT NULL
);

INSERT INTO xp_thresholds (level, xp_required, proficiency_bonus) VALUES
  (1,0,2),(2,300,2),(3,900,2),(4,2700,2),
  (5,6500,3),(6,14000,3),(7,23000,3),(8,34000,3),
  (9,48000,4),(10,64000,4),(11,85000,4),(12,100000,4),
  (13,120000,5),(14,140000,5),(15,165000,5),(16,195000,5),
  (17,225000,6),(18,265000,6),(19,305000,6),(20,355000,6)
ON CONFLICT (level) DO NOTHING;

INSERT INTO runtime_fields
  (id, owner_entity_id, field_key, value_type, default_value, allowed_values, scope, scope_per_player, description)
SELECT
  13100 + p.entity_id,
  p.entity_id,
  'xp',
  'int',
  '0'::jsonb,
  NULL,
  'permanent',
  false,
  'Total experience points. grant_xp tool increments; level recomputed via xp_thresholds.'
FROM players p
WHERE NOT EXISTS (
  SELECT 1 FROM runtime_fields rf
  WHERE rf.owner_entity_id = p.entity_id AND rf.field_key = 'xp'
);

INSERT INTO runtime_fields
  (id, owner_entity_id, field_key, value_type, default_value, allowed_values, scope, scope_per_player, description)
SELECT
  13200 + p.entity_id,
  p.entity_id,
  'level',
  'int',
  '1'::jsonb,
  NULL,
  'permanent',
  false,
  'Character level (1..20). Derived from xp via xp_thresholds; persisted for cheap reads.'
FROM players p
WHERE NOT EXISTS (
  SELECT 1 FROM runtime_fields rf
  WHERE rf.owner_entity_id = p.entity_id AND rf.field_key = 'level'
);

-- ── 0042_save_slots.sql (engine_schema) ────────────
-- Spec 36 §4 — save slots. 5 named + 1 quicksave (auto on death,
-- spec 35 combat_state='dead'). Snapshot is a single JSONB blob
-- spanning entities/runtime_values/npc_memories/player_inventory/
-- player_quests + last 200 chat_messages with a watermark id.
-- Snapshot semantics live in src/routes/saves.ts; this table is the
-- bare schema.

CREATE TABLE IF NOT EXISTS save_slots (
  id          SERIAL PRIMARY KEY,
  player_id   BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
  slot_name   TEXT NOT NULL,
  is_auto     BOOLEAN NOT NULL DEFAULT false,
  snapshot    JSONB NOT NULL,
  size_bytes  INT NOT NULL,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (player_id, slot_name)
);
CREATE INDEX IF NOT EXISTS idx_saves_player ON save_slots(player_id, created_at DESC);

-- ── 0043_dialogue_partner_and_extensions.sql (engine_schema) ────────────
-- Spec 36 §7 — surface combo + decay extensions.
--
-- §5 (dialogue partner switch) is implemented at the column level:
-- switch_dialogue_partner writes to players.dialogue_partner_id (the
-- existing source of truth) rather than introducing a parallel
-- runtime_field. Documented as deviation in EXECUTION_LOG.
--
-- §7 extends cartridge_meta.surface_combo_rules (created spec 33) with
-- water+fire→steam, acid+armor→corroded, lava+any→fire. Also extends
-- surface_decay with steam/acid/lava/web entries.
-- Spec 33 stored these as cartridge_meta JSONB rather than separate
-- surface_combo_rules / surface_effects tables, so we patch the JSONB
-- in place.

-- Extend surface_combo_rules (cartridge_meta JSONB).
UPDATE cartridge_meta
SET value = value || jsonb_build_array(
  jsonb_build_object(
    'a', 'water', 'b', 'fire',
    'result', 'steam',
    'side_effects', jsonb_build_array(
      jsonb_build_object('apply_condition', 'obscured', 'severity', 1, 'duration', 2),
      jsonb_build_object('replace_surface', 'steam', 'severity', 1)
    ),
    'narrate_hint', 'Water meets flame; the room hisses into a thick veil of steam.'
  ),
  jsonb_build_object(
    'a', 'acid', 'b', 'metal_armor',
    'result', 'corroded',
    'side_effects', jsonb_build_array(
      jsonb_build_object('apply_condition', 'corroded', 'severity', 1, 'duration', 4),
      jsonb_build_object('damage', 4, 'type', 'acid')
    ),
    'narrate_hint', 'The acid sizzles against metal; armour pits and weakens.'
  ),
  jsonb_build_object(
    'a', 'lava', 'b', 'any',
    'result', 'fire',
    'side_effects', jsonb_build_array(
      jsonb_build_object('damage', 12, 'type', 'fire'),
      jsonb_build_object('replace_surface', 'fire', 'severity', 2)
    ),
    'narrate_hint', 'Whatever crosses the lava ignites; flame remains where the heat passed.'
  )
)
WHERE key = 'surface_combo_rules'
  AND NOT (value @> '[{"a":"water","b":"fire"}]'::jsonb);

-- Extend surface_decay with new surface lifetimes.
UPDATE cartridge_meta
SET value = value || jsonb_build_object(
  'steam', jsonb_build_object('default_lifetime_turns', 2, 'severity_decay_per_turn', 1),
  'acid',  jsonb_build_object('default_lifetime_turns', 4, 'severity_decay_per_turn', 0),
  'lava',  jsonb_build_object('default_lifetime_turns', 8, 'severity_decay_per_turn', 0),
  'web',   jsonb_build_object('default_lifetime_turns', 4, 'severity_decay_per_turn', 0)
)
WHERE key = 'surface_decay'
  AND NOT (value ? 'steam');

-- ── 0044_persona_registry.sql (engine_schema) ────────────
-- Spec 37 §1 — persona-keyed bubble taxonomy.
--
-- Each entity has a persona_slug pointing into persona_archetypes.
-- The UI dispatches to one of seven bubble shapes based on the slug;
-- defaults are inferred from kind on first INSERT but the cartridge
-- author can override per entity.

CREATE TABLE IF NOT EXISTS persona_archetypes (
  slug         TEXT PRIMARY KEY,
  bubble_shape TEXT NOT NULL,
  font_family  TEXT NOT NULL,
  prose_style  TEXT NOT NULL,
  position     TEXT NOT NULL,
  decoration   JSONB NOT NULL DEFAULT '{}'::jsonb,
  notes        TEXT
);

INSERT INTO persona_archetypes (slug, bubble_shape, font_family, prose_style, position, decoration) VALUES
  ('narrator_parchment',    'parchment',     'serif-prose',  'prose',    'centered',      '{"drop_cap":true,"max_ch":70}'::jsonb),
  ('narrator_disco_prose',  'none',          'serif-prose',  'prose',    'centered',      '{"italic":true,"max_ch":70,"voice_label":true}'::jsonb),
  ('npc_rounded_tail',      'rounded_tail',  'serif-prose',  'dialogue', 'left',          '{"avatar":true,"voice_hue_var":"--persona-hue"}'::jsonb),
  ('player_echo',           'rounded',       'sans-chrome',  'echo',     'right',         '{"avatar":false,"muted":true}'::jsonb),
  ('system_pill',           'pill',          'mono-system',  'system',   'inline-center', '{"hairline_divider":true,"small_caps":true}'::jsonb),
  ('dice_capsule',          'capsule_d20',   'mono-system',  'inline',   'inline-center', '{"d20_glyph":true,"crit_glow":true}'::jsonb),
  ('lore_torn_paper',       'torn_paper',    'serif-display','prose',    'centered',      '{"texture":"parchment","drop_cap":true}'::jsonb),
  ('message_letter',        'letter',        'serif-prose',  'prose',    'centered',      '{"wax_seal":true,"signature_line":true}'::jsonb),
  ('terminal_holo',         'holographic',   'mono-system',  'system',   'centered',      '{"scanlines":true,"rim_glow":true}'::jsonb)
ON CONFLICT (slug) DO NOTHING;

ALTER TABLE entities ADD COLUMN IF NOT EXISTS persona_slug TEXT
  REFERENCES persona_archetypes(slug);

UPDATE entities SET persona_slug = 'npc_rounded_tail'
  WHERE kind = 'person' AND persona_slug IS NULL;
UPDATE entities SET persona_slug = 'player_echo'
  WHERE kind = 'player' AND persona_slug IS NULL;

-- ── 0045_directive_tags_audio_quotes.sql (engine_schema) ────────────
-- Spec 37 §2 + §3 + §8 — directive tag types, ambient beds, loading
-- quote pool, and time-of-day i18n keys for SceneBreak.
--
-- §2: directive_tag_types — strict enum of allowed `# tag: payload`
-- annotations the broker can emit. parser strips matching lines from
-- prose and emits the corresponding SSE event.
--
-- §3: ambient_beds — multi-stem ambient cartridge config. UI Howler
-- layer consumes via /api/audio/bed/:slug.
--
-- §8: loading_quotes — Pillars-style mid-load quote pool, weighted +
-- scene-tag-filterable. text_key references i18n_translations.

CREATE TABLE IF NOT EXISTS directive_tag_types (
  tag             TEXT PRIMARY KEY,
  sse_event       TEXT NOT NULL,
  payload_schema  JSONB NOT NULL,
  notes           TEXT
);

INSERT INTO directive_tag_types (tag, sse_event, payload_schema) VALUES
  ('portrait',  'portrait:set',     '{"mood":"string","entity_id":"number?"}'::jsonb),
  ('audio',     'audio:cue',        '{"cue":"string"}'::jsonb),
  ('banner',    'mode:changed',     '{"mode":"string","with":"string?"}'::jsonb),
  ('mood',      'atmosphere:mood',  '{"mood":"string"}'::jsonb),
  ('time',      'world:time_set',   '{"time":"string"}'::jsonb),
  ('weather',   'world:weather_set','{"weather":"string"}'::jsonb),
  ('cg',        'scene:cg',         '{"image":"string"}'::jsonb),
  ('focus',     'camera:focus',     '{"entity_id":"number"}'::jsonb)
ON CONFLICT (tag) DO NOTHING;

CREATE TABLE IF NOT EXISTS ambient_beds (
  slug          TEXT PRIMARY KEY,
  drone_url     TEXT,
  room_tone_url TEXT,
  foley_pool    JSONB NOT NULL DEFAULT '[]'::jsonb,
  sting_pool    JSONB NOT NULL DEFAULT '[]'::jsonb,
  cross_fade_ms INT NOT NULL DEFAULT 1500
);

