-- ── 0051_turn_telemetry_session_id_text.sql (engine_schema) ────────────
-- 0051_turn_telemetry_session_id_text.sql
--
-- Align telemetry with the runtime session contract. sessions.id,
-- chat_messages.session_id, and tool_invocations.session_id are TEXT;
-- support fixtures and imported saves may use non-UUID opaque ids.

DO $$
BEGIN
  IF EXISTS (
    SELECT 1
      FROM information_schema.columns
     WHERE table_name = 'turn_telemetry'
       AND column_name = 'session_id'
       AND data_type <> 'text'
  ) THEN
    ALTER TABLE turn_telemetry
      ALTER COLUMN session_id TYPE TEXT
      USING session_id::text;
  END IF;
END $$;

-- ── 0052_drop_default_player_display_name.sql (engine_schema) ────────────
-- 0052_drop_default_player_display_name.sql
--
-- Character creation now owns player identity. Cartridge metadata must
-- not seed a localized protagonist placeholder; anonymous bootstrap
-- accounts use a technical non-canonical name until the player creates
-- the actual character profile.

DELETE FROM cartridge_meta
 WHERE key = 'default_player_display_name_i18n';

-- ── 0053_gui_event_outbox.sql (engine_schema) ────────────
-- 0053_gui_event_outbox.sql - durable GUI event ordering/replay metadata.

CREATE TABLE IF NOT EXISTS gui_events (
  id BIGSERIAL PRIMARY KEY,
  session_id TEXT NOT NULL REFERENCES sessions(id) ON DELETE CASCADE,
  player_id BIGINT REFERENCES entities(id) ON DELETE SET NULL,
  turn_id TEXT,
  turn_index INTEGER,
  lane TEXT NOT NULL DEFAULT 'post_response',
  phase TEXT NOT NULL,
  event_type TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'ready'
    CHECK (status IN ('pending', 'ready', 'released', 'failed', 'dead')),
  message_id BIGINT REFERENCES chat_messages(id) ON DELETE SET NULL,
  release_after_message_id BIGINT REFERENCES chat_messages(id) ON DELETE SET NULL,
  dedupe_key TEXT,
  display_policy JSONB NOT NULL DEFAULT '{}'::jsonb,
  payload JSONB NOT NULL DEFAULT '{}'::jsonb,
  ready_at TIMESTAMPTZ,
  released_at TIMESTAMPTZ,
  expires_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_gui_events_session_id
  ON gui_events(session_id, id);

CREATE INDEX IF NOT EXISTS idx_gui_events_turn
  ON gui_events(session_id, turn_id, id);

CREATE INDEX IF NOT EXISTS idx_gui_events_message
  ON gui_events(message_id, id);

CREATE INDEX IF NOT EXISTS idx_gui_events_dispatch
  ON gui_events(session_id, status, turn_index, lane, id);

CREATE UNIQUE INDEX IF NOT EXISTS idx_gui_events_dedupe
  ON gui_events(session_id, dedupe_key)
  WHERE dedupe_key IS NOT NULL;

-- ── 0054_turn_ingress_queue.sql (engine_schema) ────────────
-- Spec 83: durable per-session input queue.
--
-- Player text waits here while an active turn or presentation barrier
-- owns the visible transcript. It is not copied into chat_messages
-- until the queued row is promoted and startTurnV2 begins.

CREATE TABLE IF NOT EXISTS turn_ingress_queue (
  id BIGSERIAL PRIMARY KEY,
  session_id TEXT NOT NULL REFERENCES sessions(id) ON DELETE CASCADE,
  player_id BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
  turn_id TEXT NOT NULL UNIQUE,
  status TEXT NOT NULL DEFAULT 'queued'
    CHECK (status IN ('queued', 'starting', 'running', 'done', 'cancelled', 'failed')),
  text TEXT NOT NULL,
  action_id TEXT,
  language TEXT,
  client_request_id TEXT,
  queue_index BIGINT NOT NULL,
  visible_after_turn_id TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  started_at TIMESTAMPTZ,
  finished_at TIMESTAMPTZ,
  error TEXT
);

CREATE INDEX IF NOT EXISTS idx_turn_ingress_session_status
  ON turn_ingress_queue(session_id, status, queue_index);

CREATE UNIQUE INDEX IF NOT EXISTS idx_turn_ingress_client_request
  ON turn_ingress_queue(session_id, client_request_id)
  WHERE client_request_id IS NOT NULL;

-- ── 0055_turn_telemetry_presentation_slots.sql (engine_schema) ────────────
-- 0055_turn_telemetry_presentation_slots.sql
-- Slot-level telemetry for Spec 86 post-turn presentation scheduling.

ALTER TABLE turn_telemetry
  ADD COLUMN IF NOT EXISTS slot_id BIGINT,
  ADD COLUMN IF NOT EXISTS slot_key TEXT,
  ADD COLUMN IF NOT EXISTS slot_status TEXT,
  ADD COLUMN IF NOT EXISTS deadline_ms INTEGER,
  ADD COLUMN IF NOT EXISTS expired BOOLEAN NOT NULL DEFAULT false;

CREATE INDEX IF NOT EXISTS idx_turn_telemetry_slot
  ON turn_telemetry(session_id, turn_id, slot_key, recorded_at DESC)
  WHERE slot_key IS NOT NULL;

-- ── 0056_gui_event_release_sequence.sql (engine_schema) ────────────
-- 0056_gui_event_release_sequence.sql
-- Deterministic replay order for deferred GUI events. `id` is insertion
-- order; `release_seq` is player-visible release order.

CREATE SEQUENCE IF NOT EXISTS gui_events_release_seq;

ALTER TABLE gui_events
  ADD COLUMN IF NOT EXISTS release_seq BIGINT;

UPDATE gui_events
   SET release_seq = id
 WHERE status = 'released'
   AND release_seq IS NULL;

SELECT setval(
  'gui_events_release_seq',
  GREATEST(
    COALESCE((SELECT MAX(release_seq) FROM gui_events), 0),
    COALESCE((SELECT last_value FROM gui_events_release_seq), 0)
  )
);

CREATE INDEX IF NOT EXISTS idx_gui_events_replay_release_seq
  ON gui_events(session_id, release_seq, id)
  WHERE status = 'released';

-- ── 0057_adventure_queue.sql (engine_schema) ────────────
-- 0057_adventure_queue.sql
-- Durable, replayable adventure opportunity queue for the post-turn oracle.
-- Spec 89 deliberately stores only queue/oracle metadata; materialization and
-- canon mutations are later specs.

CREATE TABLE IF NOT EXISTS adventure_queue (
  id BIGSERIAL PRIMARY KEY,
  session_id TEXT NOT NULL REFERENCES sessions(id) ON DELETE CASCADE,
  player_id BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
  turn_id TEXT,
  status TEXT NOT NULL DEFAULT 'queued'
    CHECK (status IN ('queued', 'materializing', 'ready', 'accepted', 'rejected', 'expired', 'cancelled', 'failed')),
  source TEXT NOT NULL
    CHECK (source IN ('oracle', 'quest_pacer', 'narrative_gap', 'manual_debug')),
  adventure_kind TEXT NOT NULL,
  priority INTEGER NOT NULL DEFAULT 50,
  seed TEXT NOT NULL,
  sequence INTEGER NOT NULL,
  table_id TEXT NOT NULL,
  roll_result JSONB NOT NULL DEFAULT '{}'::jsonb,
  context_snapshot JSONB NOT NULL DEFAULT '{}'::jsonb,
  blueprint JSONB,
  dedupe_key TEXT,
  available_after_turn_id TEXT,
  expires_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_adventure_queue_player_status
  ON adventure_queue(player_id, status, priority DESC, id);

CREATE INDEX IF NOT EXISTS idx_adventure_queue_session_turn
  ON adventure_queue(session_id, turn_id, id);

CREATE UNIQUE INDEX IF NOT EXISTS idx_adventure_queue_dedupe
  ON adventure_queue(session_id, player_id, dedupe_key)
  WHERE dedupe_key IS NOT NULL;

CREATE TABLE IF NOT EXISTS adventure_oracle_rolls (
  id BIGSERIAL PRIMARY KEY,
  adventure_queue_id BIGINT REFERENCES adventure_queue(id) ON DELETE CASCADE,
  session_id TEXT NOT NULL,
  player_id BIGINT NOT NULL,
  turn_id TEXT,
  seed TEXT NOT NULL,
  sequence INTEGER NOT NULL,
  die TEXT NOT NULL,
  raw_roll INTEGER NOT NULL,
  table_id TEXT NOT NULL,
  candidates JSONB NOT NULL DEFAULT '[]'::jsonb,
  selected_kind TEXT NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_adventure_oracle_rolls_queue
  ON adventure_oracle_rolls(adventure_queue_id);

CREATE INDEX IF NOT EXISTS idx_adventure_oracle_rolls_session_turn
  ON adventure_oracle_rolls(session_id, turn_id, id);

