-- ── 0073_dynamic_item_materialization.sql (engine_schema) ────────────
-- Spec 113 - backfill runtime item entities into the inventory catalogue.
--
-- Before this migration a dynamic `entities.kind='item'` row could exist only
-- as world prose. Inventory tools resolve through `items`, so take/give/use
-- actions failed even when the entity had been spawned. Fixtures and obstacles
-- stay entity-only holders.

ALTER TABLE items ADD COLUMN IF NOT EXISTS legacy_entity_id BIGINT;
CREATE UNIQUE INDEX IF NOT EXISTS idx_items_legacy_entity
  ON items(legacy_entity_id) WHERE legacy_entity_id IS NOT NULL;

INSERT INTO items
  (slug, category, weight_kg, stackable, max_stack, behaviour, legacy_entity_id)
SELECT
  LOWER(REGEXP_REPLACE(REGEXP_REPLACE(e.display_name, '''', '', 'g'), '\s+', '_', 'g')) AS slug,
  CASE
    WHEN 'currency' = ANY(e.tags) THEN 'currency'
    WHEN 'consumable' = ANY(e.tags) THEN 'consumable'
    WHEN 'weapon' = ANY(e.tags) THEN 'weapon'
    WHEN 'armor' = ANY(e.tags) THEN 'armor'
    WHEN 'quest' = ANY(e.tags)
      OR 'quest_hook' = ANY(e.tags)
      OR 'quest-item' = ANY(e.tags)
      OR 'quest_item' = ANY(e.tags)
      OR 'quest-reward' = ANY(e.tags)
      OR 'quest_reward' = ANY(e.tags)
      THEN 'quest'
    WHEN 'material' = ANY(e.tags) THEN 'material'
    ELSE 'tool'
  END AS category,
  CASE
    WHEN e.profile->>'weight_kg' ~ '^[0-9]+(\.[0-9]+)?$'
      THEN (e.profile->>'weight_kg')::numeric(5,2)
    ELSE 0::numeric(5,2)
  END AS weight_kg,
  CASE
    WHEN LOWER(COALESCE(e.profile->>'stackable', '')) IN ('true', 't', '1', 'yes')
      THEN true
    WHEN LOWER(COALESCE(e.profile->>'stackable', '')) IN ('false', 'f', '0', 'no')
      THEN false
    ELSE 'currency' = ANY(e.tags)
      OR 'consumable' = ANY(e.tags)
      OR 'material' = ANY(e.tags)
  END AS stackable,
  CASE
    WHEN e.profile->>'max_stack' ~ '^[0-9]+$'
      THEN GREATEST((e.profile->>'max_stack')::int, 1)
    WHEN 'currency' = ANY(e.tags) THEN 9999
    ELSE 1
  END AS max_stack,
  COALESCE(e.profile->'behaviour', '{}'::jsonb) AS behaviour,
  e.id AS legacy_entity_id
FROM entities e
WHERE e.kind = 'item'
  AND NOT (
    'fixture' = ANY(e.tags)
    OR 'obstacle' = ANY(e.tags)
    OR 'container' = ANY(e.tags)
    OR 'scene_fixture' = ANY(e.tags)
    OR 'scenery' = ANY(e.tags)
    OR 'decorative' = ANY(e.tags)
  )
  AND LOWER(COALESCE(e.profile->>'inventory_item', 'true')) NOT IN ('false', 'f', '0', 'no')
  AND LOWER(COALESCE(e.profile->>'inventory', 'true')) NOT IN ('false', 'f', '0', 'no')
ON CONFLICT (slug)
DO UPDATE SET
  legacy_entity_id =
    CASE
      WHEN items.legacy_entity_id IS NULL THEN EXCLUDED.legacy_entity_id
      ELSE items.legacy_entity_id
    END;

WITH placements AS (
  SELECT
    e.id AS item_entity_id,
    CASE
      WHEN e.profile->>'holder_entity_id' ~ '^[0-9]+$'
        THEN (e.profile->>'holder_entity_id')::bigint
      WHEN e.profile->>'home_id' ~ '^[0-9]+$'
        THEN (e.profile->>'home_id')::bigint
      ELSE NULL
    END AS holder_entity_id,
    CASE
      WHEN e.profile->>'count' ~ '^[0-9]+$'
        THEN GREATEST((e.profile->>'count')::int, 1)
      WHEN e.profile->>'quantity' ~ '^[0-9]+$'
        THEN GREATEST((e.profile->>'quantity')::int, 1)
      ELSE 1
    END AS count
  FROM entities e
  WHERE e.kind = 'item'
    AND NOT (
      'fixture' = ANY(e.tags)
      OR 'obstacle' = ANY(e.tags)
      OR 'container' = ANY(e.tags)
      OR 'scene_fixture' = ANY(e.tags)
      OR 'scenery' = ANY(e.tags)
      OR 'decorative' = ANY(e.tags)
    )
    AND LOWER(COALESCE(e.profile->>'inventory_item', 'true')) NOT IN ('false', 'f', '0', 'no')
    AND LOWER(COALESCE(e.profile->>'inventory', 'true')) NOT IN ('false', 'f', '0', 'no')
)
INSERT INTO inventory_entries
  (holder_entity_id, item_entity_id, count, metadata)
SELECT
  p.holder_entity_id,
  p.item_entity_id,
  p.count,
  jsonb_build_object('source', 'dynamic_item_materialization_backfill')
FROM placements p
LEFT JOIN players pl ON pl.entity_id = p.holder_entity_id
WHERE p.holder_entity_id IS NOT NULL
  AND pl.entity_id IS NULL
ON CONFLICT (holder_entity_id, item_entity_id)
DO UPDATE SET
  count = GREATEST(inventory_entries.count, EXCLUDED.count),
  metadata = COALESCE(inventory_entries.metadata, '{}'::jsonb) ||
             COALESCE(EXCLUDED.metadata, '{}'::jsonb);

-- ── 0076_turn_error_text_encoding.sql (engine_schema) ────────────
-- 0076_turn_error_text_encoding.sql
-- Normalize known player-facing mojibake error text from pre-116 builds.

UPDATE chat_messages
   SET text = 'На мгновение мир замирает: действие не удалось обработать. Повтори намерение или выбери видимый переход.'
 WHERE (
        text LIKE '%Ð¼Ð³Ð½%' AND text LIKE '%Ð´ÐµÐ¹%'
       )
    OR (
        text LIKE 'Ã%' AND text LIKE '%Â¼%' AND text LIKE '%Â´%'
       );

UPDATE gui_events
   SET payload = jsonb_set(
     payload,
     '{message}',
     to_jsonb('Соединение с моделью прервано - повтори ход. (model TLS stream reset)'::text),
     true
   )
 WHERE event_type = 'turn.error'
   AND (
        payload ->> 'message' LIKE '%TLS stream reset%'
        OR payload ->> 'message' LIKE '%Ð¡Ð¾ÐµÐ´%'
       );

UPDATE gui_events
   SET payload = jsonb_set(
     payload,
     '{message}',
     to_jsonb('Запрос отменён.'::text),
     true
   )
 WHERE event_type = 'turn.error'
   AND payload ->> 'message' LIKE '%Ð—Ð°Ð¿Ñ€Ð¾Ñ%';

UPDATE gui_events
   SET payload = jsonb_set(
     payload,
     '{message}',
     to_jsonb('Модель не успела ответить - повтори ход.'::text),
     true
   )
 WHERE event_type = 'turn.error'
   AND payload ->> 'message' LIKE '%ÐœÐ¾Ð´ÐµÐ»ÑŒ%';

UPDATE gui_events
   SET payload = jsonb_set(
     payload,
     '{message}',
     to_jsonb('Провайдер модели ограничил запросы - подожди пару секунд и повтори.'::text),
     true
   )
 WHERE event_type = 'turn.error'
   AND payload ->> 'message' LIKE '%Ð¾Ð³Ñ€Ð°Ð½Ð¸Ñ‡%';

UPDATE gui_events
   SET payload = jsonb_set(
     payload,
     '{message}',
     to_jsonb('Провайдер модели недоступен - повтори ход.'::text),
     true
   )
 WHERE event_type = 'turn.error'
   AND payload ->> 'message' LIKE '%Ð½ÐµÐ´Ð¾ÑÑ‚%';

-- ── 0085_memory_palace_loop_packets.sql (engine_schema) ────────────
-- Spec 137/138: Khash-inspired Memory Palace loop fields and packet support.
-- Keep Greenhaven's existing npc_memories/player_quests authority; add only
-- derived metadata for recall, clustering, continuity, and dynamic planning.

ALTER TABLE npc_memories
  ADD COLUMN IF NOT EXISTS memory_kind TEXT NOT NULL DEFAULT 'world_fact',
  ADD COLUMN IF NOT EXISTS memory_family TEXT NOT NULL DEFAULT 'world',
  ADD COLUMN IF NOT EXISTS source_turn_id TEXT NULL,
  ADD COLUMN IF NOT EXISTS source_tool TEXT NULL,
  ADD COLUMN IF NOT EXISTS reference_count INTEGER NOT NULL DEFAULT 0,
  ADD COLUMN IF NOT EXISTS last_referenced_at TIMESTAMPTZ NULL,
  ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  ADD COLUMN IF NOT EXISTS cluster_id TEXT NULL;

UPDATE npc_memories
   SET memory_kind = CASE
       WHEN tags && ARRAY['quest', 'quest_lesson', 'stage', 'objective']::text[] THEN 'quest_lesson'
       WHEN tags && ARRAY['trauma', 'harm', 'wound', 'sensitive']::text[] OR sensitive = true THEN 'trauma_memory'
       WHEN tags && ARRAY['promise', 'debt', 'commitment']::text[] THEN 'promise'
       WHEN tags && ARRAY['failure', 'failed', 'blocked']::text[] THEN 'failure_pattern'
       WHEN tags && ARRAY['desire', 'boundary', 'preference']::text[] THEN 'desire_or_boundary'
       WHEN tags && ARRAY['bond', 'relationship', 'strings']::text[] THEN 'bond_memory'
       ELSE COALESCE(NULLIF(memory_kind, ''), 'world_fact')
     END,
     memory_family = CASE
       WHEN tags && ARRAY['quest', 'quest_lesson', 'stage', 'objective']::text[] THEN 'quest'
       WHEN tags && ARRAY['trauma', 'harm', 'wound', 'sensitive']::text[] OR sensitive = true THEN 'safety'
       WHEN tags && ARRAY['promise', 'debt', 'commitment']::text[] THEN 'commitment'
       WHEN tags && ARRAY['failure', 'failed', 'blocked']::text[] THEN 'lesson'
       WHEN tags && ARRAY['desire', 'boundary', 'preference']::text[] THEN 'preference'
       WHEN tags && ARRAY['bond', 'relationship', 'strings']::text[] THEN 'relationship'
       ELSE COALESCE(NULLIF(memory_family, ''), 'world')
     END
 WHERE memory_kind = 'world_fact'
    OR memory_family = 'world'
    OR memory_kind IS NULL
    OR memory_family IS NULL;

CREATE INDEX IF NOT EXISTS idx_npc_memories_family_salience
  ON npc_memories (owner_entity_id, memory_family, salience DESC, importance DESC);

CREATE INDEX IF NOT EXISTS idx_npc_memories_kind_salience
  ON npc_memories (owner_entity_id, memory_kind, salience DESC, importance DESC);

CREATE INDEX IF NOT EXISTS idx_npc_memories_cluster
  ON npc_memories (cluster_id)
  WHERE cluster_id IS NOT NULL;

CREATE TABLE IF NOT EXISTS memory_threads (
  id TEXT PRIMARY KEY,
  player_id BIGINT NOT NULL,
  session_id TEXT,
  thread_kind TEXT NOT NULL DEFAULT 'session',
  title TEXT NOT NULL,
  started_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  payload JSONB NOT NULL DEFAULT '{}'::jsonb
);

CREATE INDEX IF NOT EXISTS idx_memory_threads_player_updated
  ON memory_threads (player_id, updated_at DESC);

CREATE TABLE IF NOT EXISTS memory_clusters (
  id TEXT PRIMARY KEY,
  owner_entity_id BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
  about_entity_id BIGINT NULL REFERENCES entities(id) ON DELETE SET NULL,
  memory_family TEXT NOT NULL,
  title TEXT NOT NULL,
  summary TEXT NOT NULL,
  tags TEXT[] NOT NULL DEFAULT ARRAY[]::text[],
  memory_ids JSONB NOT NULL DEFAULT '[]'::jsonb,
  salience REAL NOT NULL DEFAULT 0.5,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE memory_clusters
  ADD COLUMN IF NOT EXISTS about_entity_id BIGINT NULL REFERENCES entities(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS tags TEXT[] NOT NULL DEFAULT ARRAY[]::text[],
  ADD COLUMN IF NOT EXISTS metadata JSONB NOT NULL DEFAULT '{}'::jsonb;

CREATE INDEX IF NOT EXISTS idx_memory_clusters_owner_salience
  ON memory_clusters (owner_entity_id, salience DESC, updated_at DESC);

-- ── 0086_living_world_location_memory.sql (engine_schema) ────────────
-- Spec 139: living world around the player.
-- Location visits and first-entry bubbles are deterministic and grounded in
-- cartridge data. Actor statuses are a compact player-scoped ledger for UI and
-- prompt context; they do not replace detailed runtime fields or memory.

-- Fix-forward for early 0085 Memory Palace builds that created
-- memory_clusters before about_entity_id/tags/metadata were added. Keep this
-- here because a database that already recorded 0085 will not replay it.
ALTER TABLE memory_clusters
  ADD COLUMN IF NOT EXISTS about_entity_id BIGINT NULL REFERENCES entities(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS tags TEXT[] NOT NULL DEFAULT ARRAY[]::text[],
  ADD COLUMN IF NOT EXISTS metadata JSONB NOT NULL DEFAULT '{}'::jsonb;

CREATE TABLE IF NOT EXISTS player_location_visits (
  player_id BIGINT NOT NULL REFERENCES players(entity_id) ON DELETE CASCADE,
  location_entity_id BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
  first_seen_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  last_seen_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  visit_count INTEGER NOT NULL DEFAULT 1,
  last_intro_at TIMESTAMPTZ NULL,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  PRIMARY KEY (player_id, location_entity_id)
);

CREATE INDEX IF NOT EXISTS idx_player_location_visits_last_seen
  ON player_location_visits (player_id, last_seen_at DESC);

CREATE TABLE IF NOT EXISTS location_intro_bubbles (
  location_entity_id BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
  lang TEXT NOT NULL,
  bubble_text TEXT NOT NULL,
  source TEXT NOT NULL DEFAULT 'seeded_from_location_i18n',
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (location_entity_id, lang)
);

CREATE INDEX IF NOT EXISTS idx_location_intro_bubbles_lang
  ON location_intro_bubbles (lang, location_entity_id);

CREATE TABLE IF NOT EXISTS actor_statuses (
  player_id BIGINT NOT NULL REFERENCES players(entity_id) ON DELETE CASCADE,
  actor_entity_id BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
  status_kind TEXT NOT NULL,
  status_value TEXT NOT NULL,
  intensity REAL NOT NULL DEFAULT 1.0,
  source TEXT NOT NULL DEFAULT 'system',
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (player_id, actor_entity_id, status_kind),
  CHECK (status_kind <> ''),
  CHECK (status_value <> ''),
  CHECK (intensity >= 0 AND intensity <= 1)
);

CREATE INDEX IF NOT EXISTS idx_actor_statuses_actor
  ON actor_statuses (actor_entity_id, updated_at DESC);

WITH supported_lang(lang) AS (
  VALUES
    ('en'), ('ru'), ('uk'), ('bg'), ('sr'), ('es'), ('fr'), ('de'), ('it'),
    ('pt'), ('ro'), ('he'), ('ar'), ('fa'), ('ur'), ('hi'), ('mr'), ('ne'),
    ('bn'), ('th'), ('el'), ('hy'), ('ka'), ('ko'), ('ja'), ('zh')
),
localized AS (
  SELECT
    e.id AS location_entity_id,
    l.lang,
    COALESCE(NULLIF(e.i18n->'display_name'->>l.lang, ''), e.display_name) AS name,
    COALESCE(NULLIF(e.i18n->'summary'->>l.lang, ''), e.summary, '') AS summary
  FROM entities e
  CROSS JOIN supported_lang l
  WHERE e.kind IN ('location', 'district')
)
INSERT INTO location_intro_bubbles (location_entity_id, lang, bubble_text)
SELECT
  location_entity_id,
  lang,
  CASE
    WHEN trim(summary) <> '' THEN '@' || name || ' - ' || summary
    ELSE '@' || name
  END AS bubble_text
FROM localized
WHERE trim(name) <> ''
ON CONFLICT (location_entity_id, lang) DO UPDATE SET
  bubble_text = EXCLUDED.bubble_text,
  updated_at = now();

-- ── 0087_memory_threads_contract_parity.sql (engine_schema) ────────────
-- Align the implemented session memory-thread API with the first table shape.
-- Migration 0085 created thread_kind/payload; Spec 137 code writes kind/metadata.

ALTER TABLE memory_threads
  ADD COLUMN IF NOT EXISTS kind TEXT,
  ADD COLUMN IF NOT EXISTS metadata JSONB;

UPDATE memory_threads
   SET kind = COALESCE(kind, thread_kind, 'session'),
       metadata = COALESCE(metadata, payload, '{}'::jsonb);

ALTER TABLE memory_threads
  ALTER COLUMN kind SET DEFAULT 'session',
  ALTER COLUMN kind SET NOT NULL,
  ALTER COLUMN metadata SET DEFAULT '{}'::jsonb,
  ALTER COLUMN metadata SET NOT NULL;

CREATE INDEX IF NOT EXISTS idx_memory_threads_kind_updated
  ON memory_threads (player_id, kind, updated_at DESC);

-- ── 0088_location_first_entry_bubbles_all_languages.sql (engine_schema) ────────────
-- Spec 140: pre-generated first-entry bubbles for every playable place.
--
-- 0086 created location_intro_bubbles, but many non-English rows were only
-- English summaries copied under a translated language key. This fix-forward
-- migration makes the table complete and language-real:
--   * every location/district gets one row per supported UI language;
--   * localized summaries are used only when the cartridge actually has one;
--   * otherwise a short, diegetic, language-specific first-entry line is used;
--   * the row source is marked so later cartridge authoring can replace it.

WITH supported_lang(lang) AS (
  VALUES
    ('en'), ('ru'), ('uk'), ('bg'), ('sr'), ('es'), ('fr'), ('de'), ('it'),
    ('pt'), ('ro'), ('he'), ('ar'), ('fa'), ('ur'), ('hi'), ('mr'), ('ne'),
    ('bn'), ('th'), ('el'), ('hy'), ('ka'), ('ko'), ('ja'), ('zh')
),
localized AS (
  SELECT
    e.id AS location_entity_id,
    l.lang,
    COALESCE(NULLIF(e.i18n->'display_name'->>l.lang, ''), e.display_name) AS name,
    CASE
      WHEN l.lang = 'en' THEN COALESCE(NULLIF(e.i18n->'summary'->>'en', ''), e.summary)
      ELSE NULLIF(e.i18n->'summary'->>l.lang, '')
    END AS localized_summary
  FROM entities e
  CROSS JOIN supported_lang l
  WHERE e.kind IN ('location', 'district')
),
rendered AS (
  SELECT
    location_entity_id,
    lang,
    '@' || name ||
    CASE lang
      WHEN 'en' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'First entry. Pause at the threshold: note who is here, what is visible, where the exits lead, and which hook asks for attention first.'
      WHEN 'ru' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'Первый вход. Задержись на пороге: отметь, кто здесь, что лежит на виду, куда ведут выходы и какая зацепка просится первой.'
      WHEN 'uk' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'Перший вхід. Затримайся на порозі: відміть, хто тут, що видно, куди ведуть виходи і яка зачіпка проситься першою.'
      WHEN 'bg' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'Първо влизане. Спри на прага: отбележи кой е тук, какво се вижда, накъде водят изходите и коя следа иска внимание първа.'
      WHEN 'sr' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'Први улазак. Застани на прагу: забележи ко је овде, шта је на видику, куда воде излази и који траг први тражи пажњу.'
      WHEN 'es' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'Primera entrada. Detente en el umbral: observa quién está aquí, qué queda a la vista, adónde llevan las salidas y qué pista pide atención primero.'
      WHEN 'fr' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'Première entrée. Arrête-toi au seuil : repère qui est là, ce qui se voit, où mènent les sorties et quelle piste appelle d’abord.'
      WHEN 'de' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'Erster Eintritt. Halte an der Schwelle inne: erkenne, wer hier ist, was sichtbar liegt, wohin die Ausgänge führen und welcher Hinweis zuerst zählt.'
      WHEN 'it' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'Primo ingresso. Fermati sulla soglia: nota chi è qui, cosa si vede, dove portano le uscite e quale indizio chiede attenzione per primo.'
      WHEN 'pt' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'Primeira entrada. Pare na soleira: observe quem está aqui, o que está à vista, para onde levam as saídas e qual pista pede atenção primeiro.'
      WHEN 'ro' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'Prima intrare. Oprește-te în prag: observă cine este aici, ce se vede, unde duc ieșirile și ce indiciu cere primul atenție.'
      WHEN 'he' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'כניסה ראשונה. עצור בפתח: שים לב מי כאן, מה גלוי לעין, לאן מובילות היציאות ואיזה רמז דורש תשומת לב ראשון.'
      WHEN 'ar' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'الدخول الأول. توقّف عند العتبة: لاحظ من هنا، ما الظاهر للعين، إلى أين تقود المخارج، وأي خيط يستحق الانتباه أولاً.'
      WHEN 'fa' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'ورود نخست. روی آستانه مکث کن: ببین چه کسی اینجاست، چه چیزی پیداست، خروجی‌ها به کجا می‌روند و کدام سرنخ اول توجه می‌خواهد.'
      WHEN 'ur' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'پہلی آمد۔ دہلیز پر رک کر دیکھو: یہاں کون ہے، کیا صاف دکھائی دے رہا ہے، راستے کہاں جاتے ہیں، اور کون سا اشارہ پہلے توجہ چاہتا ہے۔'
      WHEN 'hi' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'पहला प्रवेश। दहलीज़ पर ठहरो: देखो यहाँ कौन है, क्या दिखाई दे रहा है, निकास कहाँ जाते हैं, और कौन-सा सुराग पहले ध्यान माँगता है।'
      WHEN 'mr' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'पहिला प्रवेश. उंबरठ्यावर थांब: इथे कोण आहे, काय दिसते, बाहेरचे मार्ग कुठे जातात आणि कोणता धागा आधी लक्ष मागतो ते पाहा.'
      WHEN 'ne' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'पहिलो प्रवेश। ढोकामै रोकिएर हेर: यहाँ को छ, के देखिन्छ, निकास कहाँ जान्छन्, र कुन संकेतले पहिले ध्यान माग्छ।'
      WHEN 'bn' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'প্রথম প্রবেশ। দোরগোড়ায় থামো: এখানে কে আছে, কী দেখা যাচ্ছে, বেরোনোর পথ কোথায় যায়, আর কোন সূত্র আগে নজর চায় তা দেখো।'
      WHEN 'th' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'เข้าครั้งแรก หยุดที่ธรณีประตู: สังเกตว่าใครอยู่ที่นี่ อะไรเห็นได้ชัด ทางออกพาไปไหน และเบาะแสใดควรสนใจก่อน'
      WHEN 'el' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'Πρώτη είσοδος. Στάσου στο κατώφλι: δες ποιος είναι εδώ, τι φαίνεται, πού οδηγούν οι έξοδοι και ποιο ίχνος ζητά πρώτο προσοχή.'
      WHEN 'hy' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'Առաջին մուտք։ Կանգնիր շեմին՝ նկատիր ով է այստեղ, ինչ է երևում, ուր են տանում ելքերը և որ հետքն է առաջինը ուշադրություն պահանջում։'
      WHEN 'ka' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        'პირველი შესვლა. ზღურბლთან შეჩერდი: ნახე ვინ არის აქ, რა ჩანს, სად მიდის გასასვლელები და რომელი კვალი ითხოვს პირველ ყურადღებას.'
      WHEN 'ko' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        '첫 방문. 문턱에서 멈춰 보라: 누가 있는지, 무엇이 보이는지, 출구가 어디로 이어지는지, 어떤 단서가 먼저 눈길을 끄는지 살펴라.'
      WHEN 'ja' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        '初めての入場。入口で足を止めよう。誰がいるか、何が見えるか、出口はどこへ続くか、最初に注目すべき手がかりは何かを見る。'
      WHEN 'zh' THEN ' — ' || COALESCE(localized_summary || ' ', '') ||
        '初次进入。先在门口停下：看清谁在这里、什么摆在眼前、出口通向哪里，以及哪条线索最值得先关注。'
      ELSE ' — ' || COALESCE(localized_summary || ' ', '') ||
        'First entry. Pause at the threshold: note who is here, what is visible, where the exits lead, and which hook asks for attention first.'
    END AS bubble_text
  FROM localized
  WHERE trim(name) <> ''
)
INSERT INTO location_intro_bubbles (
  location_entity_id,
  lang,
  bubble_text,
  source,
  updated_at
)
SELECT
  location_entity_id,
  lang,
  bubble_text,
  'generated_location_first_entry_v1',
  now()
FROM rendered
ON CONFLICT (location_entity_id, lang) DO UPDATE SET
  bubble_text = EXCLUDED.bubble_text,
  source = EXCLUDED.source,
  updated_at = now();

-- ── 0098_npc_memory_witness_and_private.sql (engine_schema) ────────────
-- NPC memory upgrade: witness-scoped chat history + private memory channel.
--
-- Three additions:
--   1. chat_messages.witness_entity_ids — array of NPC entity ids that
--      were physically present at the location when this message was
--      written. Used by the per-NPC dialogue view in dialogueContext so
--      each NPC sees what was said in their presence, regardless of
--      whether they were the active dialogue partner. NPCs that were
--      NOT present do not see the message and cannot reference it. Old
--      rows have NULL — the read-path falls back to author/partner
--      matching for those.
--
--   2. chat_messages text-search index — used by the new
--      `recall_partner_history` broker tool. Postgres FTS over the
--      `text` column with a Russian/English-neutral config (`simple`
--      keeps token matching unstemmed; for cyrillic that is OK because
--      we mostly query substrings, not lexemes).
--
--   3. npc_memories private-channel convention. The existing
--      `metadata` jsonb gains a `visibility` field
--      ('public' | 'private'). Public is the default and matches
--      previous behaviour — visible to other NPCs via cross-NPC
--      inference and to the player-facing UI when relevant. Private
--      memories are only ever loaded into the owner NPC's own preamble
--      and never surface to other NPCs or to the player. No schema
--      change needed since metadata is already jsonb; we add an index
--      to make the visibility filter cheap, and a tag convention
--      `tag:private` so legacy read paths that look at tags also
--      respect the channel.

ALTER TABLE chat_messages
  ADD COLUMN IF NOT EXISTS witness_entity_ids BIGINT[] DEFAULT NULL;

CREATE INDEX IF NOT EXISTS idx_chat_messages_witness_gin
  ON chat_messages USING GIN (witness_entity_ids);

CREATE INDEX IF NOT EXISTS idx_chat_messages_text_fts
  ON chat_messages USING GIN (to_tsvector('simple', text));

-- Visibility index for npc_memories. The default treats missing
-- visibility as 'public' for back-compat.
CREATE INDEX IF NOT EXISTS idx_npc_memories_visibility
  ON npc_memories ((COALESCE(metadata->>'visibility', 'public')));

-- Convenience comment documenting the new conventions so future
-- migrations don't accidentally drop them.
COMMENT ON COLUMN chat_messages.witness_entity_ids IS
  'Array of NPC entity ids that were physically present at the location '
  'when the message was written. Drives per-NPC scoped dialogue history '
  'in turnContext/dialogueContext. NULL means "unknown / legacy" — read '
  'path falls back to author/dialogue_partner matching.';

-- ── 0102_fk_fixes.sql (engine_schema) ────────────
-- Migration 0102: Fix missing FK constraints and CASCADE rules
--   * Add ON DELETE CASCADE to transitions.goto_entity_id -> entities(id)
--   * Add FK constraint on memory_threads.player_id -> players(entity_id)
--
-- GH-BUG-093: Missing CASCADE on goto_entity_id could leave dangling
-- references when a target entity is deleted.
-- GH-BUG-094: Missing FK on memory_threads.player_id violates the
-- pattern used by every other player-scoped table.

-- Part 1: Fix transitions.goto_entity_id — drop old FK, add with CASCADE.
-- We need to find and drop the auto-generated constraint name.
DO $$
DECLARE
  con_name text;
BEGIN
  SELECT con.conname INTO con_name
    FROM pg_constraint con
    JOIN pg_attribute att ON att.attnum = con.conkey[1] AND att.attrelid = 'transitions'::regclass
   WHERE con.conrelid = 'transitions'::regclass
     AND con.confrelid = 'entities'::regclass
     AND att.attname = 'goto_entity_id'
   LIMIT 1;

  IF con_name IS NOT NULL THEN
    EXECUTE format('ALTER TABLE transitions DROP CONSTRAINT %I', con_name);
  END IF;
END $$;

ALTER TABLE transitions
  ADD CONSTRAINT transitions_goto_fk
  FOREIGN KEY (goto_entity_id) REFERENCES entities(id) ON DELETE CASCADE;

-- Part 2: Add FK on memory_threads.player_id
ALTER TABLE memory_threads
  ADD CONSTRAINT memory_threads_player_fk
  FOREIGN KEY (player_id) REFERENCES players(entity_id) ON DELETE CASCADE;

-- ── 0103_forge_upsert_protected_fields.sql (engine_schema) ────────────
-- 0103_forge_upsert_protected_fields.sql
--
-- M-2 — protect computed/runtime profile fields from cartridge forge re-import.
--
-- Cartridge Forge has historically upserted entity rows with
--   ON CONFLICT (id) DO UPDATE SET ... profile = EXCLUDED.profile, ...
-- which clobbers runtime/computed profile fields that later migrations or
-- live gameplay have written (topology_parent_id, local_density,
-- local_density_summary). Migration 0094 was a per-record repair pass
-- after this damage; with this helper, the damage no longer happens on
-- re-import.
--
-- The applied immutable 0084 forge migration is left untouched (per the
-- repository migration-immutability rule). The forge exporter
-- (packages/cartridge-forge/src/exporters/exportGrinhavenSql.ts) now
-- emits  profile = gh_forge_merge_entity_profile(entities.profile,
-- EXCLUDED.profile)  instead of  profile = EXCLUDED.profile  on
-- ON CONFLICT, so every subsequent forge re-import goes through this
-- helper. 0094 is retained for historic state — DO NOT delete or edit it.

CREATE OR REPLACE FUNCTION gh_forge_merge_entity_profile(
  existing_profile jsonb,
  incoming_profile jsonb
) RETURNS jsonb
LANGUAGE sql IMMUTABLE
AS $$
  -- Start from the cartridge-author payload (or '{}' when nothing was
  -- supplied) and re-apply runtime/computed fields from the existing row
  -- so they win over the incoming cartridge values. The CASE arms only
  -- emit a key when the existing row actually had it set; this keeps the
  -- merge null/missing-key safe -- we never introduce JSON nulls for
  -- protected fields the existing row never carried.
  SELECT
    COALESCE(incoming_profile, '{}'::jsonb)
    || CASE
         WHEN existing_profile IS NOT NULL
              AND existing_profile ? 'topology_parent_id' THEN
           jsonb_build_object(
             'topology_parent_id',
             existing_profile -> 'topology_parent_id'
           )
         ELSE '{}'::jsonb
       END
    || CASE
         WHEN existing_profile IS NOT NULL
              AND existing_profile ? 'local_density' THEN
           jsonb_build_object(
             'local_density',
             existing_profile -> 'local_density'
           )
         ELSE '{}'::jsonb
       END
    || CASE
         WHEN existing_profile IS NOT NULL
              AND existing_profile ? 'local_density_summary' THEN
           jsonb_build_object(
             'local_density_summary',
             existing_profile -> 'local_density_summary'
           )
         ELSE '{}'::jsonb
       END
$$;

COMMENT ON FUNCTION gh_forge_merge_entity_profile(jsonb, jsonb) IS
  'M-2: merge an incoming cartridge profile with the existing entities.profile, '
  'preserving runtime/computed fields (topology_parent_id, local_density, '
  'local_density_summary). Missing protected keys on the existing row are '
  'not introduced as JSON nulls; incoming non-protected keys are kept as-is. '
  'Used by Cartridge Forge re-imports so 0094-style repair passes are no longer '
  'needed in fresh environments.';

-- ── 0104_density_rebuild_function.sql (engine_schema) ────────────
-- 0104_density_rebuild_function.sql
--
-- M-1 — extract the final 0093 local-density / transitive-density rebuild
-- into a reusable server-side function.
--
-- History (see docs/db/density-history.md):
--   0091 — initial density rebuild from runtime contracts. Bugged: its CTE
--          UNION-ed existing local_density.npc_ids back in, so power-center
--          duplicates survived.
--   0092 — partial repair pass; still left drift.
--   0093 — strict local_density rebuild + transitive_density_summary. This
--          is the final correct algorithm.
--   0094 — district topology repair pass needed because forge upserts in
--          0082 and the desktop-electron migration snapshots (0078-0082,
--          0096, 0099, 0100, etc.) used `profile = EXCLUDED.profile`,
--          clobbering computed fields. M-2 (migration 0103) prevents
--          that recurrence at the forge layer.
--
-- After M-2, future migrations / re-imports no longer need to repair
-- density. But the rebuild algorithm is still useful for:
--   - explicit on-demand recomputation when a cartridge ships new
--     density-affecting entities;
--   - regression tests that deliberately dirty density rows and verify
--     the rebuild restores them.
--
-- This migration defines `rebuild_local_density(target_cartridge text)`,
-- then invokes it once against the active fixture cartridge
-- ('grinhaven-full'). The first invocation against a database that has
-- already passed through 0093 + 0094 + 0103 is a no-op in terms of state
-- because the algorithm is deterministic and the inputs have not
-- changed; the function is idempotent by construction. Tests in
-- src/__tests__/migrations/invariants.test.ts exercise the idempotence
-- and dirty-row repair contracts.

CREATE OR REPLACE FUNCTION rebuild_local_density(target_cartridge text)
RETURNS TABLE(location_id bigint, npc_count int, child_count int)
LANGUAGE plpgsql
AS $$
BEGIN
  -- Phase 1: strict local density. Counts/arrays of direct ownership
  -- only (home_id / location_id / topology_parent_id pointing at this
  -- location). No UNION with previous values; this is the cache, not a
  -- denormalised mirror of the runtime UNION used by
  -- loadPresentPeopleAtLocation. Caps mirror 0093 (16 npcs, 12 scenes /
  -- events / activities, 8 quests, 24 child_locations) — parameterising
  -- the caps belongs to M-3.
  WITH strict_density AS (
    SELECT
      l.id AS loc_id,
      ARRAY(
        SELECT child.id
          FROM entities child
         WHERE child.kind IN ('location', 'district')
           AND child.profile->>'topology_parent_id' = l.id::text
           AND child.profile->>'cartridge_id' = target_cartridge
         ORDER BY child.id
         LIMIT 24
      ) AS child_location_ids,
      ARRAY(
        SELECT p.id
          FROM entities p
         WHERE p.kind = 'person'
           AND p.profile->>'home_id' = l.id::text
           AND p.profile->>'cartridge_id' = target_cartridge
         ORDER BY p.id
         LIMIT 16
      ) AS npc_ids,
      ARRAY(
        SELECT s.id
          FROM entities s
         WHERE s.kind = 'scene'
           AND s.profile->>'location_id' = l.id::text
           AND s.profile->>'cartridge_id' = target_cartridge
         ORDER BY s.id
         LIMIT 12
      ) AS scene_ids,
      ARRAY(
        SELECT e.id
          FROM entities e
         WHERE e.kind = 'event'
           AND e.profile->>'location_id' = l.id::text
           AND e.profile->>'cartridge_id' = target_cartridge
         ORDER BY e.id
         LIMIT 12
      ) AS event_ids,
      ARRAY(
        SELECT a.id
          FROM entities a
         WHERE a.kind = 'activity'
           AND a.profile->>'location_id' = l.id::text
           AND a.profile->>'cartridge_id' = target_cartridge
         ORDER BY a.id
         LIMIT 12
      ) AS activity_ids,
      ARRAY(
        SELECT q.id
          FROM entities q
         WHERE q.kind = 'quest'
           AND q.profile->>'location_id' = l.id::text
           AND q.profile->>'cartridge_id' = target_cartridge
         ORDER BY q.id
         LIMIT 8
      ) AS quest_ids
    FROM entities l
    WHERE l.kind IN ('location', 'district')
      AND l.profile->>'cartridge_id' = target_cartridge
  )
  UPDATE entities target
     SET profile = COALESCE(target.profile, '{}'::jsonb)
        || jsonb_build_object(
             'local_density',
             jsonb_build_object(
               'child_location_ids', to_jsonb(d.child_location_ids),
               'npc_ids',            to_jsonb(d.npc_ids),
               'scene_ids',          to_jsonb(d.scene_ids),
               'event_ids',          to_jsonb(d.event_ids),
               'activity_ids',       to_jsonb(d.activity_ids),
               'quest_ids',          to_jsonb(d.quest_ids)
             ),
             'local_density_summary',
             jsonb_build_object(
               'child_location_count', cardinality(d.child_location_ids),
               'npc_count',            cardinality(d.npc_ids),
               'scene_count',          cardinality(d.scene_ids),
               'event_count',          cardinality(d.event_ids),
               'activity_count',       cardinality(d.activity_ids),
               'quest_count',          cardinality(d.quest_ids)
             )
           ),
         updated_at = now()
    FROM strict_density d
   WHERE target.id = d.loc_id;

  -- Phase 2: transitive density rollup, depth-capped at 8 (matches 0093).
  WITH RECURSIVE descendants(root_id, node_id, depth) AS (
    SELECT l.id, l.id, 0
      FROM entities l
     WHERE l.kind IN ('location', 'district')
       AND l.profile->>'cartridge_id' = target_cartridge
    UNION ALL
    SELECT d.root_id, child.id, d.depth + 1
      FROM descendants d
      JOIN entities child
        ON child.kind IN ('location', 'district')
       AND child.profile->>'topology_parent_id' = d.node_id::text
       AND child.profile->>'cartridge_id' = target_cartridge
     WHERE d.depth < 8
  ),
  rollup AS (
    SELECT
      d.root_id AS loc_id,
      SUM(COALESCE((n.profile->'local_density_summary'->>'npc_count')::int, 0))      AS npc_count,
      SUM(COALESCE((n.profile->'local_density_summary'->>'scene_count')::int, 0))    AS scene_count,
      SUM(COALESCE((n.profile->'local_density_summary'->>'event_count')::int, 0))    AS event_count,
      SUM(COALESCE((n.profile->'local_density_summary'->>'activity_count')::int, 0)) AS activity_count,
      SUM(COALESCE((n.profile->'local_density_summary'->>'quest_count')::int, 0))    AS quest_count,
      COUNT(*) FILTER (WHERE d.depth > 0)                                            AS descendant_location_count,
      MAX(d.depth)                                                                   AS max_depth
      FROM descendants d
      JOIN entities n ON n.id = d.node_id
     GROUP BY d.root_id
  )
  UPDATE entities target
     SET profile = COALESCE(target.profile, '{}'::jsonb)
        || jsonb_build_object(
             'transitive_density_summary',
             jsonb_build_object(
               'npc_count',                  r.npc_count,
               'scene_count',                r.scene_count,
               'event_count',                r.event_count,
               'activity_count',             r.activity_count,
               'quest_count',                r.quest_count,
               'descendant_location_count',  r.descendant_location_count,
               'max_depth',                  r.max_depth
             )
           ),
         updated_at = now()
    FROM rollup r
   WHERE target.id = r.loc_id
     AND target.kind IN ('location', 'district');

  RETURN QUERY
    SELECT
      l.id AS location_id,
      COALESCE(
        (l.profile->'local_density_summary'->>'npc_count')::int,
        0
      ) AS npc_count,
      COALESCE(
        (l.profile->'local_density_summary'->>'child_location_count')::int,
        0
      ) AS child_count
    FROM entities l
    WHERE l.kind IN ('location', 'district')
      AND l.profile->>'cartridge_id' = target_cartridge
    ORDER BY l.id;
END;
$$;

COMMENT ON FUNCTION rebuild_local_density(text) IS
  'M-1: idempotent local_density + transitive_density_summary rebuild '
  'scoped to a single cartridge. Algorithm matches 0093 (strict local + '
  'depth-8 transitive rollup). Cap parameterisation is M-3 work.';

-- [engine-baseline] elided: cartridge content removed for clean baseline.

-- ── 0105_normalize_entity_profile_phase1_add_columns.sql (engine_schema) ────────────
-- 0105_normalize_entity_profile_phase1_add_columns.sql
--
-- ARCH-19 — Phase 1 of the entities.profile normalization.
--
-- entities.profile has historically stored 10+ heterogeneous concepts
-- (cartridge_id, topology_parent_id, origin, identity, physical,
-- background, exits, local_density, ...). ON CONFLICT rewrites
-- clobbered the whole blob; M-2 (migration 0103) plugged that for the
-- forge re-import path. ARCH-19 now pulls the hottest read fields out
-- of JSONB into normalized columns so cartridge-scope predicates,
-- topology lookups, and the dynamic/static partition can use real
-- indexes.
--
-- Staging (do NOT collapse into one pass):
--   * Phase 1 (this migration, 0105) — add columns + indexes +
--     backfill from profile/tags. Reader (cartridgeScope.ts) is NOT
--     switched; legacy JSONB keys are NOT removed.
--   * Phase 2 — switch writers (forge upsert, runtime mutations) to
--     populate the new columns alongside profile.
--   * Phase 3 — switch readers (cartridgeScope.ts predicate + every
--     callsite that reads profile->>'cartridge_id', etc.) to use the
--     columns; backfill cleanup for stale rows.
--   * Phase 4 — drop the now-unused JSONB keys.
--
-- Phase 4 requires a soak window on dev + prod with the new readers
-- in production before drop. See docs/db/entity-profile-normalization.md.

-- ──────────────────────────────────────────────────────────────────────
-- safe_to_bigint(value text) → bigint
--
-- M-5 will later replace ad-hoc regex+cast patterns across the
-- codebase. For Phase 1 we only need a small immutable helper to keep
-- this migration's backfill from crashing on malformed or
-- out-of-range topology_parent_id values inside profile.
-- ──────────────────────────────────────────────────────────────────────
CREATE OR REPLACE FUNCTION safe_to_bigint(value text)
RETURNS bigint
LANGUAGE plpgsql IMMUTABLE STRICT
AS $$
BEGIN
  IF value !~ '^-?[0-9]+$' THEN
    RETURN NULL;
  END IF;
  BEGIN
    RETURN value::bigint;
  EXCEPTION
    WHEN numeric_value_out_of_range OR invalid_text_representation THEN
      RETURN NULL;
  END;
END;
$$;

COMMENT ON FUNCTION safe_to_bigint(text) IS
  'ARCH-19 Phase 1: returns the bigint value of a text input, or NULL '
  'when the input does not match an integer pattern or overflows '
  'bigint. Immutable + strict so it can be used inside index '
  'expressions or backfill UPDATE predicates without aborting the '
  'transaction. M-5 may replace ad-hoc regex+cast patterns elsewhere.';

-- ──────────────────────────────────────────────────────────────────────
-- entities: normalized columns.
-- ──────────────────────────────────────────────────────────────────────
ALTER TABLE entities
  ADD COLUMN IF NOT EXISTS cartridge_id        text NULL,
  ADD COLUMN IF NOT EXISTS topology_parent_id  bigint NULL,
  ADD COLUMN IF NOT EXISTS dynamic_origin      boolean NOT NULL DEFAULT false;

-- topology_parent_id is an adjacency-list pointer. FK with
-- ON DELETE SET NULL so detaching a parent location/district doesn't
-- cascade-delete the children. Children whose parent is removed end
-- up with a NULL topology_parent_id and become root locations again
-- until an operator re-parents them.
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
      FROM pg_constraint
     WHERE conname = 'entities_topology_parent_id_fkey'
  ) THEN
    ALTER TABLE entities
      ADD CONSTRAINT entities_topology_parent_id_fkey
      FOREIGN KEY (topology_parent_id)
      REFERENCES entities(id)
      ON DELETE SET NULL;
  END IF;
END;
$$;

-- Narrow indexes — we only need to scan the populated rows.
CREATE INDEX IF NOT EXISTS entities_cartridge_id_idx
  ON entities(cartridge_id)
  WHERE cartridge_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS entities_topology_parent_id_idx
  ON entities(topology_parent_id)
  WHERE topology_parent_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS entities_dynamic_origin_idx
  ON entities(dynamic_origin)
  WHERE dynamic_origin = true;

-- ──────────────────────────────────────────────────────────────────────
-- Backfill from existing JSONB profile / tags.
-- ──────────────────────────────────────────────────────────────────────

-- 1) Explicit cartridge_id authored in profile.
UPDATE entities
   SET cartridge_id = profile->>'cartridge_id'
 WHERE profile ? 'cartridge_id'
   AND cartridge_id IS NULL;

-- 2) dynamic_origin: legacy entities used either
--    profile->>'origin' = 'dynamic' or the 'dynamic' tag (sometimes
--    both). Collapse to a single boolean. We do not touch the legacy
--    JSON / tag yet — Phase 4 will drop them.
UPDATE entities
   SET dynamic_origin = true
 WHERE dynamic_origin = false
   AND (
     profile->>'origin' = 'dynamic'
     OR 'dynamic' = ANY(tags)
   );

-- 3) topology_parent_id: backfill only when the JSON value safely
--    parses to bigint AND resolves to an existing location/district.
--    Anything else (garbage strings, overflows, dangling ids) stays
--    NULL; an operator can re-parent later. We use a CTE to avoid
--    evaluating safe_to_bigint twice per row.
WITH candidates AS (
  SELECT
    e.id,
    safe_to_bigint(e.profile->>'topology_parent_id') AS parent_id
    FROM entities e
   WHERE e.profile ? 'topology_parent_id'
     AND e.topology_parent_id IS NULL
)
UPDATE entities child
   SET topology_parent_id = c.parent_id
  FROM candidates c
  JOIN entities parent
    ON parent.id = c.parent_id
   AND parent.kind IN ('location', 'district')
 WHERE child.id = c.id
   AND c.parent_id IS NOT NULL;

-- 4) Preserve the current cartridgeScope.ts fallback: unmarked
--    static entities (no cartridge_id in profile, not players, not
--    dynamic, not support-smoke fixture rows) are treated as
--    quickgrin-lane content by the predicate at
--    cartridgeScope.ts:19. Replicate that here so column-based
--    readers added in Phase 3 see the same scope without breaking
--    support-smoke fixtures (they keep their tag-based scoping
--    until a later phase migrates them).
UPDATE entities
   SET cartridge_id = 'quickgrin-lane'
 WHERE cartridge_id IS NULL
   AND kind <> 'player'
   AND dynamic_origin = false
   AND NOT ('support-smoke' = ANY(tags));

-- ── 0106_normalize_entity_profile_phase3_reader_cleanup.sql (engine_schema) ────────────
-- 0106_normalize_entity_profile_phase3_reader_cleanup.sql
--
-- ARCH-19 — Phase 3 of the entities.profile normalization.
--
-- Phase 1 (0105) added the columns and ran a one-shot backfill. Phase 2
-- (writers in tools/entity.ts, tools/quest.ts, devtools fixtures,
-- forge exporter) keeps them in sync from the application side. This
-- migration is an idempotent forward-only cleanup that catches rows
-- that were added between 0105 and Phase 2 shipping, plus any
-- support-smoke fixtures whose runtime path landed a row before the
-- writer migration was wired up.
--
-- After this migration runs, the Phase 3 reader switch (rewritten
-- cartridgeScope.ts predicate) is safe: every entities row in scope
-- has cartridge_id, topology_parent_id, and dynamic_origin populated
-- to the same value the JSONB/tag-based predicate would have
-- produced. Phase 4 (drop the legacy JSONB keys + 'dynamic' tag)
-- remains soak-gated and is NOT done here.
--
-- Idempotent: safe to re-run. Every UPDATE is bounded by a WHERE
-- clause that excludes already-correct rows.

-- ──────────────────────────────────────────────────────────────────────
-- 1. cartridge_id: trim whitespace from any existing value, then
--    copy from profile->>'cartridge_id' for rows that still have a
--    NULL column.
-- ──────────────────────────────────────────────────────────────────────
UPDATE entities
   SET cartridge_id = NULLIF(TRIM(cartridge_id), '')
 WHERE cartridge_id IS NOT NULL
   AND cartridge_id <> TRIM(cartridge_id);

UPDATE entities
   SET cartridge_id = NULLIF(TRIM(profile->>'cartridge_id'), '')
 WHERE cartridge_id IS NULL
   AND profile ? 'cartridge_id'
   AND NULLIF(TRIM(profile->>'cartridge_id'), '') IS NOT NULL;

-- ──────────────────────────────────────────────────────────────────────
-- 2. support-smoke fixture entities: any non-player row tagged
--    'support-smoke' that still has no cartridge_id was seeded
--    before Phase 2B wired its writer to set the column. Stamp it
--    explicitly so the Phase 3 reader can drop the tag carve-out.
-- ──────────────────────────────────────────────────────────────────────
UPDATE entities
   SET cartridge_id = 'support-smoke'
 WHERE cartridge_id IS NULL
   AND kind <> 'player'
   AND 'support-smoke' = ANY(tags);

-- ──────────────────────────────────────────────────────────────────────
-- 3. dynamic_origin: collapse the legacy origin='dynamic' / 'dynamic'
--    tag double representation into a single column. Phase 4 will
--    drop the legacy signals; until then this just keeps the column
--    truthful.
-- ──────────────────────────────────────────────────────────────────────
UPDATE entities
   SET dynamic_origin = true
 WHERE dynamic_origin = false
   AND (
     profile->>'origin' = 'dynamic'
     OR 'dynamic' = ANY(tags)
   );

-- ──────────────────────────────────────────────────────────────────────
-- 4. topology_parent_id: recompute from profile->>'topology_parent_id'
--    via safe_to_bigint + location/district existence check, for
--    rows whose column is still NULL. Skips invalid / dangling
--    profile values silently — those stay NULL.
-- ──────────────────────────────────────────────────────────────────────
WITH candidates AS (
  SELECT
    e.id,
    safe_to_bigint(e.profile->>'topology_parent_id') AS parent_id
    FROM entities e
   WHERE e.profile ? 'topology_parent_id'
     AND e.topology_parent_id IS NULL
)
UPDATE entities child
   SET topology_parent_id = c.parent_id
  FROM candidates c
  JOIN entities parent
    ON parent.id = c.parent_id
   AND parent.kind IN ('location', 'district')
 WHERE child.id = c.id
   AND c.parent_id IS NOT NULL;

-- ──────────────────────────────────────────────────────────────────────
-- 5. Mirror the Phase 1 quickgrin-lane fallback for any non-player,
--    non-dynamic, non-support-smoke entity that's still unmarked.
--    The Phase 3 reader predicate no longer carries the
--    `cartridgeParam = 'quickgrin-lane' AND NOT (profile ?
--    'cartridge_id')` fallback, so the data has to satisfy the
--    column-based contract directly.
-- ──────────────────────────────────────────────────────────────────────
UPDATE entities
   SET cartridge_id = 'quickgrin-lane'
 WHERE cartridge_id IS NULL
   AND kind <> 'player'
   AND dynamic_origin = false
   AND NOT ('support-smoke' = ANY(tags));

-- ── 0107_density_caps_parameterized.sql (engine_schema) ────────────
-- 0107_density_caps_parameterized.sql
--
-- M-3 — make local-density rebuild caps cartridge-configurable.
--
-- 0104 introduced `rebuild_local_density(target_cartridge text)` with
-- hardcoded caps (16 npcs, 12 scenes / events / activities, 8 quests,
-- 24 child_locations). Operators or cartridge authors can now override
-- those caps without editing migrations:
--
--   UPDATE cartridge_meta
--      SET value = '{"npcs": 24, "scenes": 18}'::jsonb
--    WHERE key = 'density_caps';
--
-- Defaults stored in `cartridge_meta.density_caps` match the 0104
-- behavior bit-for-bit when missing. The TS wrapper in
-- `packages/web-server/src/density/index.ts` reads the row, sanitizes
-- per-key, and calls this function with explicit parameters.
--
-- ARCH-19 Phase 3 — this revision of the function also reads from
-- `entities.cartridge_id` and `entities.topology_parent_id` columns
-- instead of `profile->>'cartridge_id'` / `profile->>'topology_parent_id'`.
-- 0106 backfilled both columns; Phase 4 will eventually drop the legacy
-- JSONB keys.

-- The 0104 function had a single-text signature. Drop it before
-- creating the parameterized variant so a one-argument call resolves
-- unambiguously to the new function (overload disambiguation in
-- PostgreSQL fails otherwise: "function rebuild_local_density(unknown)
-- is not unique").
DROP FUNCTION IF EXISTS rebuild_local_density(text);

CREATE OR REPLACE FUNCTION rebuild_local_density(
  target_cartridge text,
  max_npcs int DEFAULT 16,
  max_child_locations int DEFAULT 24,
  max_scenes int DEFAULT 12,
  max_events int DEFAULT 12,
  max_activities int DEFAULT 12,
  max_quests int DEFAULT 8
)
RETURNS TABLE(location_id bigint, npc_count int, child_count int)
LANGUAGE plpgsql
AS $$
BEGIN
  -- Phase 1: strict local density. Counts/arrays of direct ownership
  -- only, no UNION with previous values. Limits come from the
  -- parameters so cartridges can scale them via `cartridge_meta`.
  WITH strict_density AS (
    SELECT
      l.id AS loc_id,
      ARRAY(
        SELECT child.id
          FROM entities child
         WHERE child.kind IN ('location', 'district')
           AND child.topology_parent_id = l.id
           AND child.cartridge_id = target_cartridge
         ORDER BY child.id
         LIMIT max_child_locations
      ) AS child_location_ids,
      ARRAY(
        SELECT p.id
          FROM entities p
         WHERE p.kind = 'person'
           AND p.profile->>'home_id' = l.id::text
           AND p.cartridge_id = target_cartridge
         ORDER BY p.id
         LIMIT max_npcs
      ) AS npc_ids,
      ARRAY(
        SELECT s.id
          FROM entities s
         WHERE s.kind = 'scene'
           AND s.profile->>'location_id' = l.id::text
           AND s.cartridge_id = target_cartridge
         ORDER BY s.id
         LIMIT max_scenes
      ) AS scene_ids,
      ARRAY(
        SELECT e.id
          FROM entities e
         WHERE e.kind = 'event'
           AND e.profile->>'location_id' = l.id::text
           AND e.cartridge_id = target_cartridge
         ORDER BY e.id
         LIMIT max_events
      ) AS event_ids,
      ARRAY(
        SELECT a.id
          FROM entities a
         WHERE a.kind = 'activity'
           AND a.profile->>'location_id' = l.id::text
           AND a.cartridge_id = target_cartridge
         ORDER BY a.id
         LIMIT max_activities
      ) AS activity_ids,
      ARRAY(
        SELECT q.id
          FROM entities q
         WHERE q.kind = 'quest'
           AND q.profile->>'location_id' = l.id::text
           AND q.cartridge_id = target_cartridge
         ORDER BY q.id
         LIMIT max_quests
      ) AS quest_ids
    FROM entities l
    WHERE l.kind IN ('location', 'district')
      AND l.cartridge_id = target_cartridge
  )
  UPDATE entities target
     SET profile = COALESCE(target.profile, '{}'::jsonb)
        || jsonb_build_object(
             'local_density',
             jsonb_build_object(
               'child_location_ids', to_jsonb(d.child_location_ids),
               'npc_ids',            to_jsonb(d.npc_ids),
               'scene_ids',          to_jsonb(d.scene_ids),
               'event_ids',          to_jsonb(d.event_ids),
               'activity_ids',       to_jsonb(d.activity_ids),
               'quest_ids',          to_jsonb(d.quest_ids)
             ),
             'local_density_summary',
             jsonb_build_object(
               'child_location_count', cardinality(d.child_location_ids),
               'npc_count',            cardinality(d.npc_ids),
               'scene_count',          cardinality(d.scene_ids),
               'event_count',          cardinality(d.event_ids),
               'activity_count',       cardinality(d.activity_ids),
               'quest_count',          cardinality(d.quest_ids)
             )
           ),
         updated_at = now()
    FROM strict_density d
   WHERE target.id = d.loc_id;

  -- Phase 2: transitive density rollup, depth-capped at 8 (matches
  -- 0093/0104). M-4 will instrument the depth cap with telemetry; the
  -- cap itself stays here for now.
  WITH RECURSIVE descendants(root_id, node_id, depth) AS (
    SELECT l.id, l.id, 0
      FROM entities l
     WHERE l.kind IN ('location', 'district')
       AND l.cartridge_id = target_cartridge
    UNION ALL
    SELECT d.root_id, child.id, d.depth + 1
      FROM descendants d
      JOIN entities child
        ON child.kind IN ('location', 'district')
       AND child.topology_parent_id = d.node_id
       AND child.cartridge_id = target_cartridge
     WHERE d.depth < 8
  ),
  rollup AS (
    SELECT
      d.root_id AS loc_id,
      SUM(COALESCE((n.profile->'local_density_summary'->>'npc_count')::int, 0))      AS npc_count,
      SUM(COALESCE((n.profile->'local_density_summary'->>'scene_count')::int, 0))    AS scene_count,
      SUM(COALESCE((n.profile->'local_density_summary'->>'event_count')::int, 0))    AS event_count,
      SUM(COALESCE((n.profile->'local_density_summary'->>'activity_count')::int, 0)) AS activity_count,
      SUM(COALESCE((n.profile->'local_density_summary'->>'quest_count')::int, 0))    AS quest_count,
      COUNT(*) FILTER (WHERE d.depth > 0)                                            AS descendant_location_count,
      MAX(d.depth)                                                                   AS max_depth
      FROM descendants d
      JOIN entities n ON n.id = d.node_id
     GROUP BY d.root_id
  )
  UPDATE entities target
     SET profile = COALESCE(target.profile, '{}'::jsonb)
        || jsonb_build_object(
             'transitive_density_summary',
             jsonb_build_object(
               'npc_count',                  r.npc_count,
               'scene_count',                r.scene_count,
               'event_count',                r.event_count,
               'activity_count',             r.activity_count,
               'quest_count',                r.quest_count,
               'descendant_location_count',  r.descendant_location_count,
               'max_depth',                  r.max_depth
             )
           ),
         updated_at = now()
    FROM rollup r
   WHERE target.id = r.loc_id
     AND target.kind IN ('location', 'district');

  RETURN QUERY
    SELECT
      l.id AS location_id,
      COALESCE(
        (l.profile->'local_density_summary'->>'npc_count')::int,
        0
      ) AS npc_count,
      COALESCE(
        (l.profile->'local_density_summary'->>'child_location_count')::int,
        0
      ) AS child_count
    FROM entities l
    WHERE l.kind IN ('location', 'district')
      AND l.cartridge_id = target_cartridge
