-- 0109_density_depth_cap_diagnostics_guard.sql
--
-- M-4 hardening — guard the depth-cap diagnostic INSERT against a
-- missing `migration_diagnostics` table.
--
-- 0108 added the table and the diagnostic INSERT in the same
