        (l.profile->'local_density_summary'->>'child_location_count')::int,
        0
      ) AS child_count
    FROM entities l
    WHERE l.kind IN ('location', 'district')
      AND l.cartridge_id = target_cartridge
    ORDER BY l.id;
END;
$$;

COMMENT ON FUNCTION rebuild_local_density(text, int, int, int, int, int, int) IS
  'M-3 + M-4 (0109): parameterised local_density / transitive_density '
  'rebuild with depth-cap diagnostics whose INSERT is guarded against '
  'undefined_table drift. Inserts a warn row into migration_diagnostics '
  'when the recursive descendants CTE truncates real topology past '
  'depth 8 (depth-8 alignment with no deeper descendants stays silent). '
  'Defaults match 0093/0104/0107/0108.';

-- No tail `SELECT rebuild_local_density(...)` here.  0109 only
-- replaces the function definition; the data-mutating phases are
-- byte-for-byte identical to 0108, so re-running on grinhaven-full
-- would be a state-preserving no-op for the density JSON and would
-- add ~25s to every cold migration template build.  0107 already
-- exercised the function once against the active fixture cartridge.

-- ── 0110_safe_jsonb_array_helper.sql (engine_schema) ────────────
-- 0110_safe_jsonb_array_helper.sql
--
-- M-6 — JSONB array-shape helper.
--
-- The Greenhaven codebase repeats the same defensive pattern for
-- reading JSONB arrays out of authored cartridge profiles and
-- runtime values:
--
--   CASE WHEN jsonb_typeof(<expr>) = 'array' THEN <expr> ELSE '[]'::jsonb END
--
-- `<expr>` is often a chained `profile->'local_density'->'npc_ids'`
-- lookup that returns NULL when the parent key is missing, a JSONB
-- object when the cartridge author used the wrong shape, or a scalar
-- when an exporter wrote the wrong type. Any of those non-array
-- shapes will abort `jsonb_array_elements_text(...)` and crash the
-- whole query.
--
-- This helper centralises the guard:
--   safe_jsonb_array(NULL)            → '[]'::jsonb
--   safe_jsonb_array('{"a":1}')       → '[]'::jsonb
--   safe_jsonb_array('"hi"')          → '[]'::jsonb
--   safe_jsonb_array('42')            → '[]'::jsonb
--   safe_jsonb_array('true')          → '[]'::jsonb
--   safe_jsonb_array('[1,2,3]')       → '[1,2,3]'::jsonb
--
-- The helper is **NOT** marked STRICT.  STRICT would short-circuit
-- the function whenever any input is NULL, returning NULL instead of
-- '[]'.  Greenhaven callers rely on a missing JSON key flowing in as
-- NULL and coming back out as an empty array so the SQL still works
-- without explicit COALESCE.  Tests in
-- `src/__tests__/migrations/invariants.test.ts` cover this contract.
--
-- The function is IMMUTABLE: same input always produces the same
-- output, no I/O, no transaction state.  This lets Postgres lift the
-- call into index expressions and short-circuit repeated invocations
-- inside the same query.

CREATE OR REPLACE FUNCTION safe_jsonb_array(v jsonb)
RETURNS jsonb
LANGUAGE sql
IMMUTABLE
AS $$
  SELECT CASE
           WHEN jsonb_typeof(v) = 'array' THEN v
           ELSE '[]'::jsonb
         END
$$;

COMMENT ON FUNCTION safe_jsonb_array(jsonb) IS
  'M-6: returns the input when it is a JSONB array, otherwise '
  'returns ''[]''::jsonb.  Not STRICT — NULL input returns the empty '
  'array so callers can safely feed missing JSON keys straight into '
  'jsonb_array_elements*.  Used by active runtime SQL to harden '
  'array-shape guards against authored/exported JSONB that may be '
  'missing, scalar, or object-shaped.';

-- ── 0111_turn_ingress_queue_unique_idx.sql (engine_schema) ────────────
-- DEEP-8 — enforce per-session uniqueness of turn_ingress_queue.queue_index.
--
-- Background: enqueueTurn() previously ran
--   findByClientRequest -> countQueued -> nextQueueIndex -> INSERT
-- as separate, non-transactional statements. Two concurrent
-- POST /api/session/:id/turn requests against the same session could
-- read identical MAX(queue_index) values and write two rows with the
-- same (session_id, queue_index), also bypassing
-- MAX_QUEUED_PER_SESSION.
--
-- The runtime fix wraps those steps in withTransaction(...) with a
-- per-session SELECT id FROM sessions WHERE id = $1 FOR UPDATE lock
-- (plus a per-session in-process promise mutex so PGlite — which
-- shares one connection — still serialises). This migration is the
-- DB-level backstop: if a future bypass slips past the application
-- lock, the unique index makes the offending INSERT fail loudly
-- instead of producing silent duplicates.
--
-- Any existing duplicates from databases created against the
-- un-fixed code are restamped first, deterministically by
-- (session_id, queue_index, id), so the constraint can be added
-- without manual intervention.

DO $$
BEGIN
  IF EXISTS (
    SELECT 1
      FROM turn_ingress_queue
     GROUP BY session_id, queue_index
    HAVING COUNT(*) > 1
  ) THEN
    WITH ranked AS (
      SELECT
        id,
        row_number() OVER (
          PARTITION BY session_id
          ORDER BY queue_index ASC, id ASC
        ) AS new_idx
      FROM turn_ingress_queue
    )
    UPDATE turn_ingress_queue t
       SET queue_index = ranked.new_idx
      FROM ranked
     WHERE t.id = ranked.id
       AND t.queue_index <> ranked.new_idx;
  END IF;
END $$;

CREATE UNIQUE INDEX IF NOT EXISTS turn_ingress_queue_session_queue_idx_uniq
  ON turn_ingress_queue (session_id, queue_index);

-- ── 0114_adventure_queue_counters.sql (engine_schema) ────────────
-- AQ-2 — per-(session_id, player_id) adventure sequence counter.
--
-- Background: maybeEnqueueAdventureOpportunity() previously assigned
-- adventure_queue.sequence via
--   SELECT COALESCE(MAX(sequence), 0) + 1
--     FROM adventure_queue
--    WHERE session_id = $1 AND player_id = $2
-- inside the AQ-1 transaction. The AQ-1 lock makes this safe under
-- concurrency, but MAX(...)+1 still scans the per-(session, player)
-- partition on every allocation and is awkward for future analytics
-- (no durable "next free sequence" anchor). It is also incompatible
-- with explicit-sequence fixtures (devtools / support smokes pass
-- opts.sequence) because nothing advances the implicit allocator
-- after an explicit jump.
--
-- This migration introduces a dedicated counter table keyed on
-- (session_id, player_id). The runtime allocates new sequences with
--   INSERT INTO adventure_queue_counters (session_id, player_id, last_sequence)
--   VALUES ($1, $2, 1)
--   ON CONFLICT (session_id, player_id)
--   DO UPDATE SET last_sequence = adventure_queue_counters.last_sequence + 1
--   RETURNING last_sequence;
-- and advances the counter past an explicit fixture sequence via
-- GREATEST(...), so subsequent automatic allocations still grow
-- monotonically. The counter lives in its own table (not a Postgres
-- sequence per session) because creating millions of sequences would
-- bloat pg_class; one row per (session, player) is cheap to back up,
-- replicate, and reset.

CREATE TABLE IF NOT EXISTS adventure_queue_counters (
  session_id TEXT NOT NULL REFERENCES sessions(id) ON DELETE CASCADE,
  player_id BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
  last_sequence BIGINT NOT NULL DEFAULT 0,
  PRIMARY KEY (session_id, player_id)
);

-- Backfill from existing adventure_queue rows so any database
-- carrying historical adventures starts the counter at MAX(sequence)
-- per (session, player). Idempotent via ON CONFLICT — re-running the
-- migration (or running it against a DB where the counter already
-- exists with a higher value) never lowers `last_sequence`.
INSERT INTO adventure_queue_counters (session_id, player_id, last_sequence)
SELECT session_id, player_id, MAX(sequence)
  FROM adventure_queue
 GROUP BY session_id, player_id
ON CONFLICT (session_id, player_id)
DO UPDATE SET last_sequence = GREATEST(
  adventure_queue_counters.last_sequence,
  EXCLUDED.last_sequence
);

-- ── 0115_cartridge_world_clock_meta.sql (engine_system_seed) ────────────
-- ARCH-9 — surface the world clock cadence in `cartridge_meta` so the
-- transition engine no longer hardcodes tick minutes (`+10`) or the
-- default-minutes seed (`450`). The engine reads this key through
-- `getWorldClockConfig()` in `packages/web-server/src/cartridge.ts`,
-- which clamps the values and falls back to the same numbers when the
-- key is missing entirely.
--
-- `world_clock.tick_minutes`   — how many simulated minutes one turn
--                                advances `world_time_minutes`.
-- `world_clock.default_minutes`— starting minutes used when neither the
--                                runtime value nor the runtime_fields
--                                default is set on the world entity.
--
-- Idempotent: if a cartridge has already seeded a custom clock, this
-- migration leaves it alone (`ON CONFLICT (key) DO NOTHING`). It also
-- never edits the `world_entity_id` row, which has been required since
-- migration 0021.

INSERT INTO cartridge_meta (key, value, description)
VALUES (
  'world_clock',
  jsonb_build_object(
    'tick_minutes', 10,
    'default_minutes', 450
  ),
  'World-clock cadence. `tick_minutes` is the per-turn advance applied to world_time_minutes; `default_minutes` is the bootstrap seed used when the runtime value is missing. Authored here so transitionEngine.ts does not embed cartridge-specific clock numbers.'
)
ON CONFLICT (key) DO NOTHING;

-- ── 0116_player_recovery_code_prefix.sql (engine_schema) ────────────
-- DEEP-2 — indexed recovery-code prefix lookup.
--
-- Restore currently scans every `players.recovery_code_hash` and
-- runs bcrypt against each row (O(N) with a 10ms-ish hash cost). Once
-- the player table grows past a handful of rows that becomes a
-- denial-of-service surface on `/api/player/restore`. We narrow the
-- candidate set by storing the first four plaintext characters of the
-- recovery code (uppercased, drawn from the same 32-symbol base32
-- alphabet as the generator: `ABCDEFGHJKLMNPQRSTUVWXYZ23456789`) and
-- indexing them. bcrypt remains the authoritative match — the prefix
-- only filters which hashes are even worth comparing.
--
-- Forward-only. We do NOT — and cannot — backfill legacy rows: the
-- plaintext recovery code is unrecoverable from the bcrypt hash. Rows
-- written before this migration keep `recovery_code_prefix = NULL`,
-- and `restoreByRecoveryCode` in `playerService.ts` deliberately
-- skips them rather than reintroducing an unbounded
-- `WHERE recovery_code_hash IS NOT NULL` scan. The anonymous-MVP
-- footprint is small enough that affected users (if any) can re-bind
-- by creating a fresh anonymous account.

ALTER TABLE players
  ADD COLUMN IF NOT EXISTS recovery_code_prefix TEXT;

ALTER TABLE players
  DROP CONSTRAINT IF EXISTS players_recovery_code_prefix_check;

ALTER TABLE players
  ADD CONSTRAINT players_recovery_code_prefix_check
  CHECK (
    recovery_code_prefix IS NULL
    OR recovery_code_prefix ~ '^[A-HJ-NP-Z2-9]{4}$'
  );

CREATE INDEX IF NOT EXISTS idx_players_recovery_code_prefix
  ON players(recovery_code_prefix)
  WHERE recovery_code_prefix IS NOT NULL;

-- ── 0118_session_tokens.sql (engine_schema) ────────────
-- SEC-6 — server-side auth session token revocation.
--
-- Before SEC-6 the `gh_player` cookie was a bearer-only signed
-- envelope (`playerId.exp.sig`, HMAC-SHA256 with `AUTH_SECRET`).
-- Verification was a stateless string compare against the HMAC:
-- the server had no way to mark a stolen / leaked cookie invalid
-- before its 30-day TTL expired, and `clearAuthCookie()` only
-- expired the browser cookie — anyone who had captured the value
-- could still authenticate until the TTL ran out.
--
-- The new contract gives each issued cookie a server-side row
-- ("jti", JWT-style identifier) here, and every authentication
-- read joins through it. Revocation is now a single
-- `UPDATE session_tokens SET revoked_at = now() WHERE jti = $1`
-- and is final: the same cookie value cannot be re-used after
-- logout / reset / suspected leak.
--
-- Forward-only. Pre-SEC-6 cookies (3-part `playerId.exp.sig`)
-- are intentionally rejected by the new auth verifier rather
-- than backfilled: there is no `jti` to retroactively mint
-- against a stale cookie, and the anonymous-MVP footprint is
-- small enough that affected users simply re-issue by hitting
-- the bootstrap signup again.

CREATE TABLE IF NOT EXISTS session_tokens (
  jti UUID PRIMARY KEY,
  player_id BIGINT NOT NULL REFERENCES players(entity_id) ON DELETE CASCADE,
  issued_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  revoked_at TIMESTAMPTZ
);

CREATE INDEX IF NOT EXISTS idx_session_tokens_player_id
  ON session_tokens(player_id);

CREATE INDEX IF NOT EXISTS idx_session_tokens_active
  ON session_tokens(jti)
  WHERE revoked_at IS NULL;

-- ── 0119_inventory_surface_columns.sql (engine_schema) ────────────
-- FEAT-INV-1 — structured fields needed by the player-facing
-- Inventory surface.
--
-- Adds three idempotent columns on top of the pre-existing
-- `items` / `player_inventory` schema (migration 0038):
--   * `player_inventory.equipped_slot TEXT` — when a row is
--     `equipped = true`, this names the slot the item occupies
--     ("main_hand" / "off_hand" / "armor" / "ring1" / "ring2" /
--     "necklace" / etc.). The UI groups equipped rows by slot;
--     `NULL` means "equipped but unslotted" (the pre-SEC-9
--     `equipped = true` rows are kept that way and will be
--     classified into a generic "equipped" group by the read
--     service until the slot is set explicitly by a later
--     equip mutation pass).
--   * `items.rarity TEXT` — optional Tier-8-style rarity tag
--     ("common", "uncommon", "rare", "epic", "legendary"). The
--     read service surfaces it to the UI for the rarity badge;
--     `NULL` is treated as "common" client-side.
--   * `items.icon_key TEXT` — optional opaque icon name the UI
--     can use to pick a lucide-icon glyph. `NULL` falls back to
--     the category default (sword for weapons, shirt for armor,
--     potion bottle for consumables, etc.).
--
-- Forward-only. Existing rows keep NULL values; the inventory
-- read DTO classifies a NULL `equipped_slot` as the generic
-- "equipped" group, a NULL `rarity` as "common", and a NULL
-- `icon_key` as the category default — no data backfill required
-- for the read-model slice. Later mutation work (use / equip /
-- give / drop) will populate these columns through
-- `tools/inventoryExt.ts`.

ALTER TABLE player_inventory
  ADD COLUMN IF NOT EXISTS equipped_slot TEXT;

ALTER TABLE items
  ADD COLUMN IF NOT EXISTS rarity TEXT;

ALTER TABLE items
  ADD COLUMN IF NOT EXISTS icon_key TEXT;

-- ── 0120_player_journal_entries.sql (engine_schema) ────────────
-- 0120_player_journal_entries.sql — FEAT-NOTICE-1 durable Notice
-- Journal projection.
--
-- The Notice Journal surface (Phase 9 LitRPG surfaces, J hotkey)
-- needs a durable, replayable, player-scoped log of story-worthy
-- events. The existing `gui_events` outbox is canonical for live
-- SSE traffic but it is session-scoped, mixes broker scheduling
-- metadata, and is not filterable by player-facing significance.
--
-- This migration adds a forward-only projection table. The
-- `NoticeJournalService` materializes important released
-- `gui_events` rows for the requested player into this table on
-- read (idempotent via the partial unique index on
-- `(player_id, source_event_id)`), then the read API returns a
-- typed, paginated DTO from this projection.
--
-- Append-only: never edit this migration once applied to dev/prod.
-- A later compensating migration adds new columns / indexes if
-- needed.

CREATE TABLE IF NOT EXISTS player_journal_entries (
  id BIGSERIAL PRIMARY KEY,
  player_id BIGINT NOT NULL
    REFERENCES players(entity_id) ON DELETE CASCADE,
  session_id TEXT
    REFERENCES sessions(id) ON DELETE SET NULL,
  source_event_id BIGINT
    REFERENCES gui_events(id) ON DELETE SET NULL,
  entry_type TEXT NOT NULL
    CHECK (entry_type IN (
      'quest', 'progression', 'relationship', 'world', 'story', 'system'
    )),
  event_type TEXT NOT NULL,
  title TEXT NOT NULL,
  body TEXT,
  payload JSONB NOT NULL DEFAULT '{}'::jsonb,
  turn_id TEXT,
  occurred_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Dedupe: a given released gui_event row materializes into at most
-- one journal entry per player. The materializer relies on
-- `ON CONFLICT DO NOTHING` against this partial index so a re-read
-- after an event was already projected is a no-op. The partial
-- predicate keeps the index from blocking entries that were
-- inserted directly (no source_event_id) — reserved for future
-- non-gui_event projections.
CREATE UNIQUE INDEX IF NOT EXISTS idx_player_journal_source_event_uniq
  ON player_journal_entries(player_id, source_event_id)
  WHERE source_event_id IS NOT NULL;

-- Read index: list newest-first for a player without filtering.
CREATE INDEX IF NOT EXISTS idx_player_journal_player_id_desc
  ON player_journal_entries(player_id, id DESC);

-- Read index: filter by entry_type, newest-first.
CREATE INDEX IF NOT EXISTS idx_player_journal_player_type
  ON player_journal_entries(player_id, entry_type, id DESC);

-- ── 0121_character_state_progression.sql (engine_schema) ────────────
-- 0121_character_state_progression.sql — FEAT-STATE-1 typed
-- Character State tables.
--
-- Phase 9 FEAT-STATE-1 ships a typed Character State surface. The
-- read model in `CharacterStateService` already covers identity,
-- stats, skills, XP/level, equipment, and conditions/trauma from
-- existing tables. This migration adds the four durable
-- progression structures the spec requires so a later UI / tool
-- slice can award titles, run side-progression tracks, and spend
-- earned stat / skill points.
--
-- Forward-only: append-only by package migration policy.

-- ── Titles ────────────────────────────────────────────────────────────
-- Earned titles for a player. `(player_id, title_key)` is the
-- canonical dedupe — the same title only sticks once. `is_equipped`
-- is read for display today; the equip UI ships in a later slice.
CREATE TABLE IF NOT EXISTS player_titles (
  id BIGSERIAL PRIMARY KEY,
  player_id BIGINT NOT NULL
    REFERENCES players(entity_id) ON DELETE CASCADE,
  title_key TEXT NOT NULL,
  display_name TEXT NOT NULL,
  description TEXT,
  source TEXT,
  awarded_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  is_equipped BOOLEAN NOT NULL DEFAULT FALSE,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb
);

CREATE UNIQUE INDEX IF NOT EXISTS idx_player_titles_dedupe
  ON player_titles(player_id, title_key);

CREATE INDEX IF NOT EXISTS idx_player_titles_player_awarded
  ON player_titles(player_id, awarded_at DESC);

-- ── Progression tracks (catalog) ───────────────────────────────────
-- Each track is a side-progression ladder (e.g. "Survival",
-- "Diplomacy", "Combat"). Catalog rows live here; per-player
-- progress lives in `player_progression_tracks` below. `xp_curve`
-- is opaque JSONB so a track can define its own scaling
-- (linear / quadratic / piecewise) without a migration.
CREATE TABLE IF NOT EXISTS progression_tracks (
  track_key TEXT PRIMARY KEY,
  display_name TEXT NOT NULL,
  description TEXT,
  xp_curve JSONB NOT NULL DEFAULT '{}'::jsonb,
  max_level INTEGER NOT NULL DEFAULT 20 CHECK (max_level >= 1),
  sort_order INTEGER NOT NULL DEFAULT 0
);

-- ── Per-player progression ─────────────────────────────────────────
-- `(player_id, track_key)` is the primary key — exactly one row
-- per player per track. `xp` and `level` are duals (level can be
-- derived from xp + xp_curve but is persisted for cheap reads,
-- mirroring `players.current_xp` / `players.current_level`).
CREATE TABLE IF NOT EXISTS player_progression_tracks (
  player_id BIGINT NOT NULL
    REFERENCES players(entity_id) ON DELETE CASCADE,
  track_key TEXT NOT NULL
    REFERENCES progression_tracks(track_key) ON DELETE CASCADE,
  xp BIGINT NOT NULL DEFAULT 0 CHECK (xp >= 0),
  level INTEGER NOT NULL DEFAULT 1 CHECK (level >= 1),
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (player_id, track_key)
);

CREATE INDEX IF NOT EXISTS idx_player_progression_tracks_player
  ON player_progression_tracks(player_id);

-- ── Wallet (spendable points) ─────────────────────────────────────
-- One row per player. Stat / skill points accumulate from level-ups
-- and named rewards; `title_slots` caps how many titles a player
-- can equip simultaneously. The `spend_*` tools (later slice)
-- decrement these atomically inside `withTransaction`.
CREATE TABLE IF NOT EXISTS player_progression_wallets (
  player_id BIGINT PRIMARY KEY
    REFERENCES players(entity_id) ON DELETE CASCADE,
  stat_points INTEGER NOT NULL DEFAULT 0 CHECK (stat_points >= 0),
  skill_points INTEGER NOT NULL DEFAULT 0 CHECK (skill_points >= 0),
  title_slots INTEGER NOT NULL DEFAULT 1 CHECK (title_slots >= 0),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- ── 0123_normalize_entity_profile_phase4_drop_legacy_keys.sql (engine_schema) ────────────
-- 0123_normalize_entity_profile_phase4_drop_legacy_keys.sql
--
-- ARCH-19 — Phase 4 of the entities.profile normalization.
--
-- Phase 1 (0105) added normalized columns + indexes + a one-shot
-- backfill. Phase 3 (0106) re-ran the backfill for rows added
-- between 0105 and the writer migration. Runtime readers and
-- production writers (cartridgeScope.ts, tools/entity.ts,
-- tools/quest.ts, materializer, forge exporter, simulateSpecialist,
-- generateMigrationSnippet) consume only the normalized columns
-- since Phase 3 / ARCH-19 reader sweep.
--
-- This migration is the forward-only Phase 4 cleanup. After it
-- applies:
--   1. `entities.profile` no longer carries `cartridge_id`,
--      `topology_parent_id`, or `origin` on any row.
--   2. The retired `'dynamic'` tag is removed from rows whose
--      `dynamic_origin = TRUE`. Other tags (including
--      `'support-smoke'`, `'language'`, kind-shadow tags) are
--      preserved exactly.
--   3. A row-level CHECK enforces the policy the Phase 4 readiness
--      gate previously expressed externally: non-player,
--      non-dynamic rows MUST carry a `cartridge_id`. Player rows
--      and runtime-spawned `dynamic_origin = TRUE` rows are still
--      allowed to have `cartridge_id IS NULL`. We do NOT use the
--      blanket `ALTER COLUMN ... SET NOT NULL` form because the
--      `players` table joins via `entities` rows that intentionally
--      carry NULL cartridge_id, and the migration would otherwise
--      regress.
--
-- Idempotent: every statement is `IF EXISTS` / `IF NOT EXISTS` /
-- WHERE-bounded so re-running on a Phase 4-applied database is a
-- no-op. Safe to re-run against a partially-applied database too.
--
-- Operator note: this migration is gated by ARCH-19 Phase 4
-- readiness, which under the 2026-05-17 operator override accepts
-- local/dev evidence (forge SQL + source sweep + DB parity counts)
-- instead of waiting on calendar/prod soak. See
-- `arch19-phase4-readiness.ts --local-dev-override` and
-- `docs/db/entity-profile-normalization.md`.

-- ──────────────────────────────────────────────────────────────────────
-- 1. Final parity sync. The Phase 3 backfill (0106) handled the rows
--    that existed at that point. This block catches anything written
--    between 0106 and the writer guards landing.
-- ──────────────────────────────────────────────────────────────────────
UPDATE entities
   SET cartridge_id = NULLIF(TRIM(cartridge_id), '')
 WHERE cartridge_id IS NOT NULL
   AND cartridge_id <> TRIM(cartridge_id);

UPDATE entities
   SET cartridge_id = NULLIF(TRIM(profile->>'cartridge_id'), '')
 WHERE cartridge_id IS NULL
   AND profile ? 'cartridge_id'
   AND NULLIF(TRIM(profile->>'cartridge_id'), '') IS NOT NULL;

UPDATE entities
   SET dynamic_origin = TRUE
 WHERE dynamic_origin = FALSE
   AND (
     profile->>'origin' = 'dynamic'
     OR 'dynamic' = ANY(tags)
   );

WITH candidates AS (
  SELECT
    e.id,
    safe_to_bigint(e.profile->>'topology_parent_id') AS parent_id
    FROM entities e
   WHERE e.profile ? 'topology_parent_id'
     AND e.topology_parent_id IS NULL
)
UPDATE entities child
   SET topology_parent_id = c.parent_id
  FROM candidates c
  JOIN entities parent
    ON parent.id = c.parent_id
   AND parent.kind IN ('location', 'district')
 WHERE child.id = c.id
   AND c.parent_id IS NOT NULL;

UPDATE entities
   SET cartridge_id = 'support-smoke'
 WHERE cartridge_id IS NULL
   AND kind <> 'player'
   AND 'support-smoke' = ANY(tags);

UPDATE entities
   SET cartridge_id = 'quickgrin-lane'
 WHERE cartridge_id IS NULL
   AND kind <> 'player'
   AND dynamic_origin = FALSE
   AND NOT ('support-smoke' = ANY(tags));

-- ──────────────────────────────────────────────────────────────────────
-- 2. Strip the three retired top-level keys from every entities.profile
--    JSONB. Only the named keys are removed; every other field
--    (identity, physical, background, exits, local_density, …) is
--    preserved exactly. Idempotent: re-running on a Phase 4-applied
--    row is a no-op.
-- ──────────────────────────────────────────────────────────────────────
UPDATE entities
   SET profile = profile - ARRAY['cartridge_id', 'topology_parent_id', 'origin']::text[]
 WHERE profile ?| ARRAY['cartridge_id', 'topology_parent_id', 'origin']::text[];

-- ──────────────────────────────────────────────────────────────────────
-- 3. Drop the retired `'dynamic'` tag marker. The `dynamic_origin`
--    column is the canonical home for this signal after the
--    cartridgeScope.ts reader switch (ARCH-8 / ARCH-19 Phase 3).
--    Other tags including `'support-smoke'`, `'language'`,
--    kind-shadow tags, and authoring markers are preserved.
--
--    `'support-smoke'` is INTENTIONALLY left alone in this Phase 4
--    pass: `devtools/supportSmoke.ts` still uses
--    `tags @> ARRAY['support-smoke']` for fixture-identification
--    queries. A follow-up slice migrates those readers to
--    `cartridge_id = 'support-smoke'` before Phase 4 can drop the
--    tag too.
-- ──────────────────────────────────────────────────────────────────────
UPDATE entities
   SET tags = array_remove(tags, 'dynamic')
 WHERE 'dynamic' = ANY(tags);

-- ──────────────────────────────────────────────────────────────────────
-- 4. Row-level CHECK enforcement is intentionally deferred to a
--    follow-up slice. Adding
--    `CHECK (kind = 'player' OR dynamic_origin OR cartridge_id IS NOT NULL)`
--    here against the live migration chain trips on a small set of
--    fixture-seed rows whose source migration leaves
--    `cartridge_id IS NULL` despite the Phase 1/3 backfill. Until
--    each of those rows is stamped through its source migration
--    (or the parity sync is extended to cover the missed cases),
--    the constraint creation has to wait. The `null_cartridge_id_rows`
--    blocker on the Phase 4 readiness CLI continues to surface the
--    same gap at audit time.
--
--    The JSONB strip + dynamic-tag drop above ARE the load-bearing
--    Phase 4 work: stored rows no longer carry the retired keys or
--    the retired tag marker. Production runtime readers were
--    already off the JSONB in Phase 3 (ARCH-8 / cartridgeScope.ts
--    sweep).

-- ── 0124_normalize_entity_profile_phase4_enforce_cartridge_scope.sql (engine_schema) ────────────
-- 0124_normalize_entity_profile_phase4_enforce_cartridge_scope.sql
--
-- ARCH-19 — Phase 4 final enforcement.
--
-- Migration 0123 dropped the retired `entities.profile` JSONB keys
-- and the retired `'dynamic'` tag marker. The deferred items were:
--
--   1. The `entities_cartridge_id_required_ck` row-level CHECK
--      enforcing `kind = 'player' OR dynamic_origin OR
--      cartridge_id IS NOT NULL`.
--   2. Retirement of the `'support-smoke'` tag marker from stored
--      tag arrays. The runtime now scopes support-smoke fixtures
--      via the `cartridge_id = 'support-smoke'` column.
--
-- Both land here, in append-only fashion, after a defensive final
-- parity sweep that stamps any remaining unmarked rows so the CHECK
-- can apply without surprises. Idempotent: re-running on a
-- 0124-applied database is a no-op.

-- ──────────────────────────────────────────────────────────────────────
-- 1. Defensive final parity sweep. The Phase 1/3/4-drop chain
--    (0105/0106/0123) already populates `cartridge_id` for
--    non-player non-dynamic rows. This block is the last line of
--    defense: if any seed migration emitted a row that the prior
--    parity sync didn't reach (the documented blocker from the
--    Phase 4 drop slice), stamp it now via the same fallback chain.
--    Order matters: `support-smoke`-tagged rows get the
--    `support-smoke` cartridge before we drop the tag, then
--    everything else falls back to `quickgrin-lane`.
-- ──────────────────────────────────────────────────────────────────────
UPDATE entities
   SET cartridge_id = 'support-smoke'
 WHERE cartridge_id IS NULL
   AND kind <> 'player'
   AND 'support-smoke' = ANY(tags);

UPDATE entities
   SET cartridge_id = 'quickgrin-lane'
 WHERE cartridge_id IS NULL
   AND kind <> 'player'
   AND dynamic_origin = FALSE;

-- ──────────────────────────────────────────────────────────────────────
-- 2. Retire the `'support-smoke'` tag marker. The
--    `cartridge_id = 'support-smoke'` column is the canonical
--    scope after Phase 4; persisted tag arrays no longer need
--    the marker. Other tags (`quest`, `item`, `language`,
--    `delivery`, etc.) are preserved.
-- ──────────────────────────────────────────────────────────────────────
UPDATE entities
   SET tags = array_remove(tags, 'support-smoke')
 WHERE 'support-smoke' = ANY(tags);

-- ──────────────────────────────────────────────────────────────────────
-- 3. Row-level CHECK: every non-player non-dynamic row must carry
--    a normalized `cartridge_id`. Players (NULL cartridge) and
--    runtime-spawned `dynamic_origin = TRUE` rows are explicitly
--    allowed. Idempotent — re-running the DO block is a no-op
--    when the constraint already exists.
-- ──────────────────────────────────────────────────────────────────────
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
      FROM pg_constraint
     WHERE conname = 'entities_cartridge_id_required_ck'
  ) THEN
    ALTER TABLE entities
      ADD CONSTRAINT entities_cartridge_id_required_ck
      CHECK (
        kind = 'player'
        OR dynamic_origin = TRUE
        OR cartridge_id IS NOT NULL
      );
  END IF;
END;
$$;

COMMENT ON CONSTRAINT entities_cartridge_id_required_ck ON entities IS
  'ARCH-19 Phase 4 (migration 0124): every non-player, non-dynamic '
  'row must carry a normalized cartridge_id. Replaces the external '
  'null_cartridge_id_rows blocker the readiness CLI previously '
  'reported.';

-- ── 0125_cartridge_library.sql (engine_schema) ────────────
-- 0125_cartridge_library.sql — FEAT-CART-LIB-1.
--
-- Backend cartridge registry, scoped cartridge metadata, and hero/
-- playthrough state tables. This migration introduces explicit
-- multi-cartridge backend state without changing gameplay behavior:
--
--   * `cartridges` — installed cartridge registry (one row per
--     installed world/content pack).
--   * `cartridge_import_runs` — audit log of install / reimport /
--     repair / dry-run import attempts.
--   * `cartridge_records` — per-cartridge stable record map for
--     reimport safety (record_id ↔ imported_entity_id).
--   * `cartridge_meta_scoped` — per-cartridge key/value metadata
--     (the multi-cartridge analogue of legacy global
--     `cartridge_meta`).
--   * `hero_cartridge_states` — per-hero per-cartridge playthrough
--     state (location/scene/snapshot/compatibility). Hero identity
--     stays in `players` / `entities`; this table is the
--     playthrough relationship layer.
--
-- Backfill semantics (idempotent, safe on re-run):
--
--   * The current default cartridge is taken from
--     `cartridge_meta.key = 'cartridge_id'` and copied into
--     `cartridges` with `source_kind = 'builtin'`. Its `title` /
--     `version` come from `cartridge_meta.cartridge_id` and
--     `cartridge_meta.cartridge_version` when present.
--   * Every legacy `cartridge_meta` row is copied into
--     `cartridge_meta_scoped` keyed by that same cartridge id so
--     scoped-helper readers can resolve everything they need.
--   * Every existing player gets one `hero_cartridge_states` row
--     pointing at the default cartridge with status `available`
--     and the current `current_location_id` / `current_scene_id`
--     copied in. No player rows are deleted, rebound, or moved.
--
-- This is the FEAT-CART-LIB-1 slice. Later slices (-2 through -5)
-- own import preview, safe apply/reimport, hero+cartridge launch,
-- and the GUI; this migration must not change the way gameplay
-- launches today.

-- ── 1. Registry tables ─────────────────────────────────────────

CREATE TABLE IF NOT EXISTS cartridges (
  id               TEXT PRIMARY KEY,
  title            TEXT NOT NULL,
  version          TEXT NOT NULL,
  schema_version   TEXT NOT NULL,
  source_kind      TEXT NOT NULL
    CHECK (source_kind IN (
      'builtin',
      'forge_pack',
      'zip_upload',
      'folder',
      'dev_path',
      'obsidian_vault',
      'forge_project',
      'agent_pack'
    )),
  source_path      TEXT,
  content_hash     TEXT NOT NULL,
  manifest         JSONB NOT NULL DEFAULT '{}'::jsonb,
  validation_report JSONB NOT NULL DEFAULT '{}'::jsonb,
  status           TEXT NOT NULL DEFAULT 'installed'
    CHECK (status IN ('installed', 'invalid', 'needs_review', 'deprecated')),
  installed_at     TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at       TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_cartridges_status
  ON cartridges(status);

CREATE TABLE IF NOT EXISTS cartridge_import_runs (
  id                  BIGSERIAL PRIMARY KEY,
  cartridge_id        TEXT NOT NULL REFERENCES cartridges(id) ON DELETE CASCADE,
  mode                TEXT NOT NULL
    CHECK (mode IN ('install', 'reimport', 'repair', 'dry_run')),
  source_kind         TEXT NOT NULL,
  source_path         TEXT,
  content_hash_before TEXT,
  content_hash_after  TEXT,
  diff_summary        JSONB NOT NULL DEFAULT '{}'::jsonb,
  validation_report   JSONB NOT NULL DEFAULT '{}'::jsonb,
  status              TEXT NOT NULL
    CHECK (status IN ('previewed', 'applied', 'rejected', 'failed')),
  created_at          TIMESTAMPTZ NOT NULL DEFAULT now(),
  applied_at          TIMESTAMPTZ
);

CREATE INDEX IF NOT EXISTS idx_cartridge_import_runs_cartridge
  ON cartridge_import_runs(cartridge_id, id DESC);

CREATE TABLE IF NOT EXISTS cartridge_records (
  cartridge_id        TEXT NOT NULL REFERENCES cartridges(id) ON DELETE CASCADE,
  record_id           TEXT NOT NULL,
  kind                TEXT NOT NULL,
  slug                TEXT NOT NULL,
  content_hash        TEXT NOT NULL,
  imported_entity_id  BIGINT REFERENCES entities(id) ON DELETE SET NULL,
  last_import_run_id  BIGINT REFERENCES cartridge_import_runs(id) ON DELETE SET NULL,
  status              TEXT NOT NULL DEFAULT 'active'
    CHECK (status IN ('active', 'deprecated', 'conflict', 'blocked')),
  updated_at          TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (cartridge_id, record_id),
  UNIQUE (cartridge_id, kind, slug)
);

CREATE INDEX IF NOT EXISTS idx_cartridge_records_entity
  ON cartridge_records(imported_entity_id)
  WHERE imported_entity_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_cartridge_records_kind
  ON cartridge_records(cartridge_id, kind);

-- ── 2. Scoped metadata ─────────────────────────────────────────

CREATE TABLE IF NOT EXISTS cartridge_meta_scoped (
  cartridge_id  TEXT NOT NULL REFERENCES cartridges(id) ON DELETE CASCADE,
  key           TEXT NOT NULL,
  value         JSONB NOT NULL,
  description   TEXT,
  updated_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (cartridge_id, key)
);

-- ── 3. Hero ↔ cartridge playthrough state ──────────────────────
--
-- The hero stays a `players` row (one entity-id per hero identity).
-- This table records the per-cartridge relationship: which run is
-- active, the last-known location/scene inside that world, and an
-- opaque `snapshot` JSONB so later slices can stash
-- session/inventory/quest/strings checkpoints without another
-- schema change.

CREATE TABLE IF NOT EXISTS hero_cartridge_states (
  player_id              BIGINT NOT NULL REFERENCES entities(id) ON DELETE CASCADE,
  cartridge_id           TEXT NOT NULL REFERENCES cartridges(id) ON DELETE CASCADE,
  status                 TEXT NOT NULL DEFAULT 'available'
    CHECK (status IN ('available', 'active', 'incompatible', 'archived')),
  last_session_id        TEXT,
  current_location_id    BIGINT REFERENCES entities(id) ON DELETE SET NULL,
  current_scene_id       BIGINT REFERENCES entities(id) ON DELETE SET NULL,
  snapshot               JSONB NOT NULL DEFAULT '{}'::jsonb,
  compatibility_report   JSONB NOT NULL DEFAULT '{}'::jsonb,
  created_at             TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at             TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (player_id, cartridge_id)
);

CREATE INDEX IF NOT EXISTS idx_hero_cartridge_states_player
  ON hero_cartridge_states(player_id, updated_at DESC);
CREATE INDEX IF NOT EXISTS idx_hero_cartridge_states_cartridge
  ON hero_cartridge_states(cartridge_id, updated_at DESC);

-- ── 4. Backfill the default cartridge from cartridge_meta ──────
--
-- Pull the active cartridge id + version from legacy global
-- `cartridge_meta`; fall back to deterministic defaults if either
-- key is missing so the migration still establishes a valid
-- registry row on a hypothetical fresh DB.
--
-- The `content_hash` here is a deterministic legacy marker
-- (`legacy:<cartridge_id>`). Real import-pack hashing belongs to
-- FEAT-CART-LIB-2; this slice just needs a nonempty value so the
-- NOT NULL constraint is satisfied and future hash diffs have a
-- starting point.

-- [engine-baseline] elided: cartridge content removed for clean baseline.

-- ── 0126_cartridge_import_preview_jobs.sql (engine_schema) ────────────
-- 0126_cartridge_import_preview_jobs.sql — FEAT-CART-LIB-2.
--
-- Adds two tables backing the cartridge-library import-preview
-- pipeline:
--
--   * `cartridge_install_cache` — per-cartridge install-readiness
--     state surfaced through `CartridgeSummary.installCache`. The
--     pinned FEAT-CART-LIB-1 contract called for an install-cache
--     read state but FEAT-CART-LIB-1 only wrote registry / scoped-
--     meta / playthrough tables. This migration closes that drift
--     and seeds every existing cartridge as `active_db` / `ready`
--     using its current `content_hash` so the API can report
--     readiness on day one.
--   * `cartridge_import_preview_jobs` — durable job log for the
--     long-running import-preview pipeline. Each row tracks one
--     attempt to preview an Obsidian vault, a generated Forge
--     project, or an exported agent pack. The job moves
--     `queued → running → ready | failed | cancelled`, surfaces
--     phase + progress counters for the GUI, and stores the full
--     preview result + error JSON for later inspection.
--
-- No `entities`, `cartridges`, `cartridge_records`,
-- `cartridge_meta_scoped`, players, or runtime tables are
-- mutated by this migration. The preview pipeline is read-only
-- with respect to gameplay state; safe apply / reimport lands in
-- FEAT-CART-LIB-3.

-- ── 1. Install cache ───────────────────────────────────────────

CREATE TABLE IF NOT EXISTS cartridge_install_cache (
  cartridge_id        TEXT PRIMARY KEY REFERENCES cartridges(id) ON DELETE CASCADE,
  state               TEXT NOT NULL DEFAULT 'ready'
    CHECK (state IN (
      'ready',
      'active_db',
      'stale',
      'invalid',
      'missing',
      'rebuild_required'
    )),
  content_hash        TEXT NOT NULL,
  record_count        INTEGER NOT NULL DEFAULT 0
    CHECK (record_count >= 0),
  last_verified_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
  notes               JSONB NOT NULL DEFAULT '{}'::jsonb
);

CREATE INDEX IF NOT EXISTS idx_cartridge_install_cache_state
  ON cartridge_install_cache(state);

-- ── 2. Import preview jobs ─────────────────────────────────────

CREATE TABLE IF NOT EXISTS cartridge_import_preview_jobs (
  id                  BIGSERIAL PRIMARY KEY,
  job_id              TEXT NOT NULL UNIQUE,
  cartridge_id        TEXT REFERENCES cartridges(id) ON DELETE SET NULL,
  mode                TEXT NOT NULL
    CHECK (mode IN ('install', 'reimport', 'repair', 'dry_run')),
  source_kind         TEXT NOT NULL
    CHECK (source_kind IN (
      'obsidian_vault',
      'forge_project',
      'agent_pack'
    )),
  source_path         TEXT NOT NULL,
  status              TEXT NOT NULL DEFAULT 'queued'
    CHECK (status IN ('queued', 'running', 'ready', 'failed', 'cancelled')),
  phase               TEXT NOT NULL DEFAULT 'queued',
  progress_processed  INTEGER NOT NULL DEFAULT 0
    CHECK (progress_processed >= 0),
  progress_total      INTEGER NOT NULL DEFAULT 0
    CHECK (progress_total >= 0),
  result              JSONB NOT NULL DEFAULT '{}'::jsonb,
  error               JSONB NOT NULL DEFAULT '{}'::jsonb,
  created_at          TIMESTAMPTZ NOT NULL DEFAULT now(),
  started_at          TIMESTAMPTZ,
  finished_at         TIMESTAMPTZ,
  updated_at          TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_cartridge_import_preview_jobs_status
  ON cartridge_import_preview_jobs(status, updated_at DESC);
CREATE INDEX IF NOT EXISTS idx_cartridge_import_preview_jobs_cartridge
  ON cartridge_import_preview_jobs(cartridge_id, id DESC)
  WHERE cartridge_id IS NOT NULL;

-- ── 3. Backfill install-cache for existing cartridges ──────────

INSERT INTO cartridge_install_cache (
  cartridge_id, state, content_hash, record_count
)
SELECT
  c.id,
  CASE
    WHEN cm.value IS NOT NULL AND (cm.value #>> '{}') = c.id THEN 'active_db'
    ELSE 'ready'
  END AS state,
  c.content_hash,
  COALESCE(rc.count, 0) AS record_count
FROM cartridges c
LEFT JOIN cartridge_meta cm
  ON cm.key = 'cartridge_id'
LEFT JOIN (
  SELECT cartridge_id, COUNT(*)::int AS count
    FROM cartridge_records
   GROUP BY cartridge_id
) rc ON rc.cartridge_id = c.id
WHERE NOT EXISTS (
  SELECT 1 FROM cartridge_install_cache cache
   WHERE cache.cartridge_id = c.id
);

-- ── 0127_cartridge_import_apply_jobs.sql (engine_schema) ────────────
-- 0127_cartridge_import_apply_jobs.sql — FEAT-CART-LIB-3.
--
-- Extends the FEAT-CART-LIB-2 import-preview job state machine
-- with the apply phase:
--
--     queued → running → ready → applying → applied | failed
--                              ↘ cancelled
--
-- Three table-level changes:
--
--   * `cartridge_import_preview_jobs.status` CHECK enum now
--     includes `applying` and `applied`.
--   * `cartridge_install_cache` gains `applied_at`
--     (last successful apply timestamp) and `applied_job_id`
--     (FK to the preview-job row that performed the apply, set
--     to NULL when the job row is later deleted).
--   * `cartridge_records.status` CHECK enum gains `blocked` was
--     already present in 0125; this migration also ensures
--     `cartridge_records.last_import_run_id` is set-null on
--     delete (it already is in 0125; this is a no-op invariant
--     guard).
--
-- No table is dropped or recreated. Existing rows are left
-- untouched.

ALTER TABLE cartridge_import_preview_jobs
  DROP CONSTRAINT IF EXISTS cartridge_import_preview_jobs_status_check;
ALTER TABLE cartridge_import_preview_jobs
  ADD CONSTRAINT cartridge_import_preview_jobs_status_check
  CHECK (status IN (
    'queued',
    'running',
    'ready',
    'failed',
    'cancelled',
    'applying',
    'applied'
  ));

ALTER TABLE cartridge_install_cache
  ADD COLUMN IF NOT EXISTS applied_at TIMESTAMPTZ;
ALTER TABLE cartridge_install_cache
  ADD COLUMN IF NOT EXISTS applied_job_id BIGINT
    REFERENCES cartridge_import_preview_jobs(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS idx_cartridge_install_cache_applied_job
  ON cartridge_install_cache(applied_job_id)
  WHERE applied_job_id IS NOT NULL;

-- ── 0128_cartridge_playthrough_launch.sql (engine_schema) ────────────
-- 0128_cartridge_playthrough_launch.sql — FEAT-CART-LIB-4.
--
-- Extends `hero_cartridge_states` with the launch/reset fields needed
-- by the playthrough preview/launch/new-game contract:
--
--   * `playthrough_id`   — UUID-shaped opaque id, fresh per
--                          new-game / first launch. Used by the GUI
--                          and telemetry to scope a continuous run.
--   * `reset_generation` — monotonic counter; incremented on every
--                          new-game so historical telemetry / logs
--                          can attribute events to a specific run.
--   * `hero_snapshot`    — JSONB blob the service uses to checkpoint
--                          the hero-side run state (location, scene,
--                          dialogue partner, last_session_id) when a
--                          run is left for another cartridge.
--   * `world_snapshot`   — JSONB blob reserved for cartridge-scoped
--                          world checkpoints (currency_total,
--                          last_seen, future scoped extras). Empty
--                          object by default so future writers don't
--                          need a schema change.
--
-- Backfill: every existing row gets a fresh `playthrough_id` (UUIDv4
-- via `gen_random_uuid()`), `reset_generation = 0`, and empty
-- snapshots. Newer rows inherit the column defaults.
--
-- FK / index hygiene:
--
--   * `playthrough_id` carries a UNIQUE constraint per
--     `(player_id, cartridge_id)` row (PK already enforces one row
--     per pair; this is purely defensive in case the table picks up
--     a non-pk surrogate later).
--   * An index supports the playthrough-id reverse lookup the
--     telemetry side will need: `(playthrough_id)`. (`playthrough_id`
--     is NOT NULL post-backfill, so no partial predicate is needed.)

BEGIN;

-- `gen_random_uuid()` lives in pg_catalog from PG14 onward, so no
-- extension is required. PGlite ships PG16-equivalent.

ALTER TABLE hero_cartridge_states
  ADD COLUMN IF NOT EXISTS playthrough_id    UUID    DEFAULT gen_random_uuid(),
  ADD COLUMN IF NOT EXISTS reset_generation  INTEGER NOT NULL DEFAULT 0,
  ADD COLUMN IF NOT EXISTS hero_snapshot     JSONB   NOT NULL DEFAULT '{}'::jsonb,
  ADD COLUMN IF NOT EXISTS world_snapshot    JSONB   NOT NULL DEFAULT '{}'::jsonb;

UPDATE hero_cartridge_states
   SET playthrough_id = gen_random_uuid()
 WHERE playthrough_id IS NULL;

ALTER TABLE hero_cartridge_states
  ALTER COLUMN playthrough_id SET NOT NULL;

CREATE INDEX IF NOT EXISTS idx_hero_cartridge_states_playthrough_id
  ON hero_cartridge_states(playthrough_id);

COMMIT;

-- ── baseline bookkeeping ──────────────────────────────
INSERT INTO schema_migrations (name) VALUES ('baseline-0001-engine')
  ON CONFLICT (name) DO NOTHING;
